  insert into public.numerology_ledger_releases (locale, version, status, notes)
  insert into public.numerology_contents (release_id, content_type, number_key, payload_jsonb)
  values
    (v_release_id, 'universal_day', '1', $json${"title": "N\u0103ng l\u01b0\u1ee3ng kh\u1edfi \u0111\u1ea7u", "energy_theme": "H\u00f4m nay mang n\u0103ng l\u01b0\u1ee3ng c\u1ee7a s\u1ef1 ti\u00ean phong v\u00e0 kh\u1edfi \u0111\u1ed9ng chu k\u1ef3 m\u1edbi.", "meaning": "Trong th\u1ea7n s\u1ed1 h\u1ecdc, Universal Day 1 t\u01b0\u1ee3ng tr\u01b0ng cho s\u1ef1 kh\u1edfi \u0111\u1ea7u, t\u00ednh \u0111\u1ed9c l\u1eadp v\u00e0 tinh th\u1ea7n l\u00e3nh \u0111\u1ea1o. \u0110\u00e2y l\u00e0 th\u1eddi \u0111i\u1ec3m n\u0103ng l\u01b0\u1ee3ng th\u00fac \u0111\u1ea9y m\u1ecdi ng\u01b0\u1eddi h\u00e0nh \u0111\u1ed9ng ch\u1ee7 \u0111\u1ed9ng h\u01a1n v\u00e0 m\u1edf ra nh\u1eefng h\u01b0\u1edbng \u0111i m\u1edbi.", "energy_manifestation": "Trong ng\u00e0y mang n\u0103ng l\u01b0\u1ee3ng s\u1ed1 1, b\u1ea1n c\u00f3 th\u1ec3 nh\u1eadn th\u1ea5y m\u1ecdi th\u1ee9 di\u1ec5n ra v\u1edbi t\u1ed1c \u0111\u1ed9 nhanh h\u01a1n. Nhi\u1ec1u ng\u01b0\u1eddi c\u1ea3m th\u1ea5y th\u00f4i th\u00fac b\u1eaft \u0111\u1ea7u d\u1ef1 \u00e1n m\u1edbi, \u0111\u01b0a ra quy\u1ebft \u0111\u1ecbnh nhanh ho\u1eb7c mu\u1ed1n t\u1ef1 m\u00ecnh d\u1eabn d\u1eaft t\u00ecnh hu\u1ed1ng thay v\u00ec ch\u1edd \u0111\u1ee3i.", "keywords": ["Kh\u1edfi \u0111\u1ea7u", "Ti\u00ean phong", "Ch\u1ee7 \u0111\u1ed9ng", "Quy\u1ebft \u0111o\u00e1n"]}$json$::jsonb),
    (v_release_id, 'universal_day', '2', $json${"title": "N\u0103ng l\u01b0\u1ee3ng c\u00e2n b\u1eb1ng", "energy_theme": "H\u00f4m nay ph\u00f9 h\u1ee3p cho h\u1ee3p t\u00e1c, \u0111\u1ed3ng h\u00e0nh v\u00e0 \u0111i\u1ec1u ch\u1ec9nh nh\u1ecbp \u0111i\u1ec7u c\u1ea3m x\u00fac.", "meaning": "Universal Day 2 t\u01b0\u1ee3ng tr\u01b0ng cho s\u1ef1 h\u00f2a h\u1ee3p, ngo\u1ea1i giao v\u00e0 k\u1ebft n\u1ed1i. N\u0103ng l\u01b0\u1ee3ng ng\u00e0y n\u00e0y thi\u00ean v\u1ec1 l\u1eafng nghe, ph\u1ed1i h\u1ee3p v\u00e0 x\u00e2y d\u1ef1ng m\u1ed1i quan h\u1ec7 b\u1ec1n v\u1eefng.", "energy_manifestation": "B\u1ea1n c\u00f3 th\u1ec3 nh\u1eadn th\u1ea5y c\u00e1c cu\u1ed9c trao \u0111\u1ed5i c\u1ea7n s\u1ef1 tinh t\u1ebf h\u01a1n b\u00ecnh th\u01b0\u1eddng. \u0110\u00e2y l\u00e0 th\u1eddi \u0111i\u1ec3m thu\u1eadn l\u1ee3i \u0111\u1ec3 \u0111\u00e0m ph\u00e1n, h\u00e0n g\u1eafn v\u00e0 l\u00e0m vi\u1ec7c nh\u00f3m thay v\u00ec h\u00e0nh \u0111\u1ed9ng m\u1ed9t m\u00ecnh.", "keywords": ["H\u00f2a h\u1ee3p", "K\u1ebft n\u1ed1i", "L\u1eafng nghe", "H\u1ee3p t\u00e1c"]}$json$::jsonb),
    (v_release_id, 'universal_day', '3', $json${"title": "N\u0103ng l\u01b0\u1ee3ng bi\u1ec3u \u0111\u1ea1t", "energy_theme": "H\u00f4m nay m\u1edf ra d\u00f2ng ch\u1ea3y s\u00e1ng t\u1ea1o, giao ti\u1ebfp v\u00e0 ni\u1ec1m vui.", "meaning": "Universal Day 3 g\u1eafn v\u1edbi kh\u1ea3 n\u0103ng th\u1ec3 hi\u1ec7n b\u1ea3n th\u00e2n, c\u1ea3m h\u1ee9ng ngh\u1ec7 thu\u1eadt v\u00e0 tinh th\u1ea7n t\u00edch c\u1ef1c. \u0110\u00e2y l\u00e0 ng\u00e0y t\u1ed1t \u0111\u1ec3 chia s\u1ebb \u00fd t\u01b0\u1edfng v\u00e0 k\u1ebft n\u1ed1i x\u00e3 h\u1ed9i.", "energy_manifestation": "B\u1ea1n c\u00f3 th\u1ec3 th\u1ea5y b\u1ea3n th\u00e2n d\u1ec5 n\u00f3i ra suy ngh\u0129 h\u01a1n, ho\u1eb7c xu\u1ea5t hi\u1ec7n nhi\u1ec1u c\u01a1 h\u1ed9i tr\u00ecnh b\u00e0y, thuy\u1ebft ph\u1ee5c, s\u00e1ng t\u1ea1o n\u1ed9i dung. Tinh th\u1ea7n vui v\u1ebb lan t\u1ecfa m\u1ea1nh trong m\u00f4i tr\u01b0\u1eddng xung quanh.", "keywords": ["S\u00e1ng t\u1ea1o", "Giao ti\u1ebfp", "C\u1ea3m h\u1ee9ng", "Vui v\u1ebb"]}$json$::jsonb),
    (v_release_id, 'universal_day', '4', $json${"title": "N\u0103ng l\u01b0\u1ee3ng x\u00e2y n\u1ec1n", "energy_theme": "H\u00f4m nay nh\u1ea5n m\u1ea1nh s\u1ef1 k\u1ef7 lu\u1eadt, c\u1ea5u tr\u00fac v\u00e0 t\u00ednh th\u1ef1c t\u1ebf.", "meaning": "Universal Day 4 t\u01b0\u1ee3ng tr\u01b0ng cho n\u1ec1n t\u1ea3ng, tr\u1eadt t\u1ef1 v\u00e0 lao \u0111\u1ed9ng b\u1ec1n b\u1ec9. \u0110\u00e2y l\u00e0 th\u1eddi \u0111i\u1ec3m ph\u00f9 h\u1ee3p \u0111\u1ec3 x\u00e2y h\u1ec7 th\u1ed1ng, l\u1eadp k\u1ebf ho\u1ea1ch v\u00e0 ho\u00e0n thi\u1ec7n vi\u1ec7c dang d\u1edf.", "energy_manifestation": "B\u1ea1n c\u00f3 th\u1ec3 c\u1ea3m th\u1ea5y c\u1ea7n t\u1ed5 ch\u1ee9c l\u1ea1i c\u00f4ng vi\u1ec7c, \u01b0u ti\u00ean vi\u1ec7c quan tr\u1ecdng v\u00e0 x\u1eed l\u00fd t\u1eebng b\u01b0\u1edbc ch\u1eafc ch\u1eafn. K\u1ebft qu\u1ea3 s\u1ebd \u0111\u1ebfn t\u1eeb s\u1ef1 \u1ed5n \u0111\u1ecbnh h\u01a1n l\u00e0 t\u1ed1c \u0111\u1ed9.", "keywords": ["K\u1ef7 lu\u1eadt", "\u1ed4n \u0111\u1ecbnh", "T\u1ed5 ch\u1ee9c", "Th\u1ef1c t\u1ebf"]}$json$::jsonb),
    (v_release_id, 'universal_day', '5', $json${"title": "N\u0103ng l\u01b0\u1ee3ng thay \u0111\u1ed5i", "energy_theme": "H\u00f4m nay m\u1edf r\u1ed9ng tr\u1ea3i nghi\u1ec7m m\u1edbi v\u00e0 khuy\u1ebfn kh\u00edch linh ho\u1ea1t.", "meaning": "Universal Day 5 \u0111\u1ea1i di\u1ec7n cho t\u1ef1 do, chuy\u1ec3n \u0111\u1ed9ng v\u00e0 kh\u00e1m ph\u00e1. N\u0103ng l\u01b0\u1ee3ng s\u1ed1 5 gi\u00fap b\u1ea1n d\u1ec5 th\u00edch nghi v\u00e0 d\u00e1m th\u1eed \u0111i\u1ec1u m\u1edbi.", "energy_manifestation": "B\u1ea1n c\u00f3 th\u1ec3 g\u1eb7p nh\u1eefng thay \u0111\u1ed5i b\u1ea5t ng\u1edd v\u1ec1 l\u1ecbch tr\u00ecnh ho\u1eb7c c\u01a1 h\u1ed9i m\u1edbi xu\u1ea5t hi\u1ec7n nhanh. \u0110\u00e2y l\u00e0 ng\u00e0y t\u1ed1t \u0111\u1ec3 \u0111i\u1ec1u ch\u1ec9nh h\u01b0\u1edbng \u0111i, th\u1eed nghi\u1ec7m c\u00e1ch l\u00e0m m\u1edbi v\u00e0 m\u1edf r\u1ed9ng k\u1ebft n\u1ed1i.", "keywords": ["Linh ho\u1ea1t", "T\u1ef1 do", "Kh\u00e1m ph\u00e1", "\u0110\u1ed5i m\u1edbi"]}$json$::jsonb),
    (v_release_id, 'universal_day', '6', $json${"title": "N\u0103ng l\u01b0\u1ee3ng ch\u0103m s\u00f3c", "energy_theme": "H\u00f4m nay t\u1eadp trung v\u00e0o tr\u00e1ch nhi\u1ec7m, t\u00ecnh c\u1ea3m v\u00e0 s\u1ef1 g\u1eafn k\u1ebft.", "meaning": "Universal Day 6 t\u01b0\u1ee3ng tr\u01b0ng cho y\u00eau th\u01b0\u01a1ng, nu\u00f4i d\u01b0\u1ee1ng v\u00e0 h\u00e0i h\u00f2a trong gia \u0111\u00ecnh ho\u1eb7c c\u1ed9ng \u0111\u1ed3ng. \u0110\u00e2y l\u00e0 ng\u00e0y ph\u00f9 h\u1ee3p \u0111\u1ec3 c\u00e2n b\u1eb1ng gi\u1eefa cho \u0111i v\u00e0 t\u1ef1 ch\u0103m s\u00f3c.", "energy_manifestation": "B\u1ea1n c\u00f3 th\u1ec3 th\u1ea5y c\u00e1c ch\u1ee7 \u0111\u1ec1 v\u1ec1 gia \u0111\u00ecnh, quan h\u1ec7 th\u00e2n thi\u1ebft ho\u1eb7c tr\u00e1ch nhi\u1ec7m c\u00e1 nh\u00e2n n\u1ed5i b\u1eadt h\u01a1n. N\u0103ng l\u01b0\u1ee3ng n\u00e0y khuy\u1ebfn kh\u00edch h\u00e0nh \u0111\u1ed9ng t\u1eed t\u1ebf v\u00e0 ch\u1eefa l\u00e0nh.", "keywords": ["Y\u00eau th\u01b0\u01a1ng", "Tr\u00e1ch nhi\u1ec7m", "H\u1ed7 tr\u1ee3", "H\u00e0i h\u00f2a"]}$json$::jsonb),
    (v_release_id, 'universal_day', '7', $json${"title": "N\u0103ng l\u01b0\u1ee3ng chi\u00eam nghi\u1ec7m", "energy_theme": "H\u00f4m nay ph\u00f9 h\u1ee3p \u0111\u1ec3 ch\u1eadm l\u1ea1i, quan s\u00e1t v\u00e0 \u0111\u00e0o s\u00e2u n\u1ed9i t\u00e2m.", "meaning": "Universal Day 7 \u0111\u1ea1i di\u1ec7n cho tr\u00ed tu\u1ec7, tr\u1ef1c gi\u00e1c v\u00e0 chi\u1ec1u s\u00e2u tinh th\u1ea7n. \u0110\u00e2y l\u00e0 th\u1eddi \u0111i\u1ec3m t\u1ed1t \u0111\u1ec3 nghi\u00ean c\u1ee9u, suy ng\u1eabm v\u00e0 t\u00ecm c\u00e2u tr\u1ea3 l\u1eddi t\u1eeb b\u00ean trong.", "energy_manifestation": "B\u1ea1n c\u00f3 th\u1ec3 c\u1ea3m th\u1ea5y c\u1ea7n t\u0129nh l\u1eb7ng h\u01a1n \u0111\u1ec3 suy ngh\u0129 r\u00f5 r\u00e0ng. C\u00e1c quy\u1ebft \u0111\u1ecbnh quan tr\u1ecdng th\u01b0\u1eddng t\u1ed1t h\u01a1n khi \u0111\u01b0\u1ee3c c\u00e2n nh\u1eafc k\u1ef9 thay v\u00ec ph\u1ea3n \u1ee9ng t\u1ee9c th\u1eddi.", "keywords": ["Tr\u1ef1c gi\u00e1c", "N\u1ed9i t\u00e2m", "Suy ng\u1eabm", "Th\u1ea5u hi\u1ec3u"]}$json$::jsonb),
    (v_release_id, 'universal_day', '8', $json${"title": "N\u0103ng l\u01b0\u1ee3ng th\u00e0nh t\u1ef1u", "energy_theme": "H\u00f4m nay \u01b0u ti\u00ean hi\u1ec7u qu\u1ea3, m\u1ee5c ti\u00eau r\u00f5 r\u00e0ng v\u00e0 n\u0103ng l\u1ef1c qu\u1ea3n tr\u1ecb.", "meaning": "Universal Day 8 t\u01b0\u1ee3ng tr\u01b0ng cho quy\u1ec1n l\u1ef1c, th\u00e0nh c\u00f4ng v\u1eadt ch\u1ea5t v\u00e0 t\u01b0 duy chi\u1ebfn l\u01b0\u1ee3c. \u0110\u00e2y l\u00e0 ng\u00e0y ph\u00f9 h\u1ee3p \u0111\u1ec3 t\u1eadp trung v\u00e0o k\u1ebft qu\u1ea3 c\u1ee5 th\u1ec3 v\u00e0 tr\u00e1ch nhi\u1ec7m l\u1edbn.", "energy_manifestation": "B\u1ea1n c\u00f3 th\u1ec3 nh\u1eadn th\u1ea5y c\u00e1c v\u1ea5n \u0111\u1ec1 v\u1ec1 c\u00f4ng vi\u1ec7c, t\u00e0i ch\u00ednh, hi\u1ec7u su\u1ea5t tr\u1edf n\u00ean n\u1ed5i b\u1eadt. N\u0103ng l\u01b0\u1ee3ng n\u00e0y th\u00fac \u0111\u1ea9y b\u1ea1n h\u00e0nh \u0111\u1ed9ng quy\u1ebft li\u1ec7t, c\u00f3 s\u1ed1 li\u1ec7u v\u00e0 c\u00f3 \u0111\u1ecbnh h\u01b0\u1edbng d\u00e0i h\u1ea1n.", "keywords": ["Th\u00e0nh t\u1ef1u", "Hi\u1ec7u su\u1ea5t", "Chi\u1ebfn l\u01b0\u1ee3c", "T\u00e0i ch\u00ednh"]}$json$::jsonb),
    (v_release_id, 'universal_day', '9', $json${"title": "N\u0103ng l\u01b0\u1ee3ng ho\u00e0n t\u1ea5t", "energy_theme": "H\u00f4m nay l\u00e0 nh\u1ecbp n\u0103ng l\u01b0\u1ee3ng c\u1ee7a kh\u00e9p l\u1ea1i, bu\u00f4ng b\u1ecf v\u00e0 chuy\u1ec3n giao.", "meaning": "Universal Day 9 \u0111\u1ea1i di\u1ec7n cho s\u1ef1 ho\u00e0n th\u00e0nh chu k\u1ef3, l\u00f2ng nh\u00e2n \u00e1i v\u00e0 t\u1ea7m nh\u00ecn r\u1ed9ng h\u01a1n. \u0110\u00e2y l\u00e0 l\u00fac ph\u00f9 h\u1ee3p \u0111\u1ec3 k\u1ebft th\u00fac \u0111i\u1ec1u c\u0169 v\u00e0 chu\u1ea9n b\u1ecb cho giai \u0111o\u1ea1n m\u1edbi.", "energy_manifestation": "B\u1ea1n c\u00f3 th\u1ec3 th\u1ea5y nhu c\u1ea7u d\u1ecdn d\u1eb9p vi\u1ec7c t\u1ed3n \u0111\u1ecdng, k\u1ebft th\u00fac m\u1ed1i b\u1eadn t\u00e2m k\u00e9o d\u00e0i ho\u1eb7c tha th\u1ee9 cho \u0111i\u1ec1u \u0111\u00e3 qua. N\u0103ng l\u01b0\u1ee3ng s\u1ed1 9 gi\u00fap b\u1ea1n nh\u1eb9 h\u01a1n \u0111\u1ec3 b\u01b0\u1edbc ti\u1ebfp.", "keywords": ["Ho\u00e0n t\u1ea5t", "Bu\u00f4ng b\u1ecf", "Nh\u00e2n \u00e1i", "Chuy\u1ec3n h\u00f3a"]}$json$::jsonb),
    (v_release_id, 'daily_message', '1', $json${"variants": [{"main_message": "H\u00f4m nay l\u00e0 ng\u00e0y \u0111\u1ec3 b\u1ea1n d\u1eabn d\u1eaft", "sub_message": "N\u0103ng l\u01b0\u1ee3ng s\u1ed1 1 mang \u0111\u1ebfn cho b\u1ea1n s\u1ee9c m\u1ea1nh ti\u00ean phong. \u0110\u1eebng ch\u1edd \u0111\u1ee3i - h\u00e3y h\u00e0nh \u0111\u1ed9ng ngay!", "hint_action": "B\u1eaft \u0111\u1ea7u m\u1ed9t d\u1ef1 \u00e1n m\u1edbi ho\u1eb7c \u0111\u01b0a ra quy\u1ebft \u0111\u1ecbnh quan tr\u1ecdng m\u00e0 b\u1ea1n \u0111\u00e3 tr\u00ec ho\u00e3n", "thinking": "H\u00e3y d\u00e0nh v\u00e0i ph\u00fat \u0111\u1ec3 suy ng\u1eabm v\u1ec1 th\u00f4ng \u0111i\u1ec7p n\u00e0y. N\u00f3 c\u00f3 \u00fd ngh\u0129a g\u00ec v\u1edbi t\u00ecnh hu\u1ed1ng hi\u1ec7n t\u1ea1i c\u1ee7a b\u1ea1n? L\u00e0m th\u1ebf n\u00e0o b\u1ea1n c\u00f3 th\u1ec3 \u00e1p d\u1ee5ng l\u1eddi khuy\u00ean n\u00e0y v\u00e0o cu\u1ed9c s\u1ed1ng h\u00f4m nay?", "tips": ["Vi\u1ebft th\u00f4ng \u0111i\u1ec7p n\u00e0y v\u00e0o nh\u1eadt k\u00fd \u0111\u1ec3 theo d\u00f5i s\u1ef1 ph\u00e1t tri\u1ec3n", "\u0110\u1eb7t th\u00f4ng \u0111i\u1ec7p l\u00e0m l\u1eddi nh\u1eafc trong ng\u00e0y \u0111\u1ec3 gi\u1eef t\u00e2m tr\u00ed t\u1eadp trung", "Chia s\u1ebb v\u1edbi ng\u01b0\u1eddi th\u00e2n n\u1ebfu th\u00f4ng \u0111i\u1ec7p n\u00e0y c\u00f3 \u00fd ngh\u0129a \u0111\u1eb7c bi\u1ec7t", "Quay l\u1ea1i v\u00e0o cu\u1ed1i ng\u00e0y \u0111\u1ec3 xem th\u00f4ng \u0111i\u1ec7p \u0111\u00e3 gi\u00fap b\u1ea1n nh\u01b0 th\u1ebf n\u00e0o"]}, {"main_message": "Kh\u1eb3ng \u0111\u1ecbnh b\u1ea3n th\u00e2n c\u1ee7a b\u1ea1n", "sub_message": "S\u1ef1 t\u1ef1 tin \u0111ang \u1edf \u0111\u1ec9nh cao. H\u00e3y \u0111\u1ec3 th\u1ebf gi\u1edbi th\u1ea5y \u0111\u01b0\u1ee3c con ng\u01b0\u1eddi th\u1eadt c\u1ee7a b\u1ea1n.", "hint_action": "Chia s\u1ebb \u00fd t\u01b0\u1edfng s\u00e1ng t\u1ea1o ho\u1eb7c kh\u1edfi x\u01b0\u1edbng m\u1ed9t ho\u1ea1t \u0111\u1ed9ng m\u00e0 b\u1ea1n \u0111am m\u00ea", "thinking": "H\u00e3y d\u00e0nh v\u00e0i ph