    (v_release_id, 'lucky_number', '1', $json${"title": "Kh\u1edfi \u0111\u1ea7u & L\u00e3nh \u0111\u1ea1o", "message": "H\u00f4m nay ph\u00f9 h\u1ee3p \u0111\u1ec3 b\u1ea1n ch\u1ee7 \u0111\u1ed9ng m\u1edf \u0111\u01b0\u1eddng v\u00e0 ra quy\u1ebft \u0111\u1ecbnh.", "meaning": "S\u1ed1 1 \u0111\u1ea1i di\u1ec7n cho s\u1ef1 kh\u1edfi \u0111\u1ea7u m\u1edbi, tinh th\u1ea7n ti\u00ean phong v\u00e0 kh\u1ea3 n\u0103ng d\u1eabn d\u1eaft. N\u0103ng l\u01b0\u1ee3ng n\u00e0y khuy\u1ebfn kh\u00edch b\u1ea1n h\u00e0nh \u0111\u1ed9ng \u0111\u1ed9c l\u1eadp, r\u00f5 r\u00e0ng v\u00e0 quy\u1ebft \u0111o\u00e1n.", "how_to_use": ["\u0110\u1eb7t 1 m\u1ee5c ti\u00eau \u01b0u ti\u00ean v\u00e0 ho\u00e0n t\u1ea5t b\u01b0\u1edbc \u0111\u1ea7u ti\u00ean ngay trong h\u00f4m nay.", "Ch\u1ee7 \u0111\u1ed9ng \u0111\u1ec1 xu\u1ea5t \u00fd t\u01b0\u1edfng thay v\u00ec ch\u1edd \u0111\u1ee3i ng\u01b0\u1eddi kh\u00e1c.", "\u01afu ti\u00ean c\u00e1c quy\u1ebft \u0111\u1ecbnh c\u1ea7n s\u1ef1 d\u1ee9t kho\u00e1t v\u00e0 tinh th\u1ea7n ti\u00ean phong."], "situations": ["Ch\u1ecdn s\u1ed1", "B\u1ed1c th\u0103m", "Ch\u1ecdn gh\u1ebf / ph\u00f2ng", "\u0110\u01b0a ra l\u1ef1a ch\u1ecdn quan tr\u1ecdng"]}$json$::jsonb),
    (v_release_id, 'lucky_number', '2', $json${"title": "H\u1ee3p t\u00e1c & H\u00f2a h\u1ee3p", "message": "N\u0103ng l\u01b0\u1ee3ng ng\u00e0y h\u00f4m nay thi\u00ean v\u1ec1 k\u1ebft n\u1ed1i v\u00e0 ph\u1ed1i h\u1ee3p nh\u1ecbp nh\u00e0ng.", "meaning": "S\u1ed1 2 \u0111\u1ea1i di\u1ec7n cho s\u1ef1 c\u00e2n b\u1eb1ng, tinh t\u1ebf trong c\u1ea3m x\u00fac v\u00e0 kh\u1ea3 n\u0103ng h\u1ee3p t\u00e1c. \u0110\u00e2y l\u00e0 n\u0103ng l\u01b0\u1ee3ng c\u1ee7a l\u1eafng nghe, \u0111\u1ed3ng c\u1ea3m v\u00e0 t\u1ea1o h\u00f2a h\u1ee3p trong m\u1ed1i quan h\u1ec7.", "how_to_use": ["L\u1eafng nghe s\u00e2u tr\u01b0\u1edbc khi ph\u1ea3n h\u1ed3i trong c\u00e1c cu\u1ed9c trao \u0111\u1ed5i quan tr\u1ecdng.", "\u01afu ti\u00ean l\u00e0m vi\u1ec7c nh\u00f3m v\u00e0 \u0111\u1ed3ng b\u1ed9 k\u1ef3 v\u1ecdng gi\u1eefa c\u00e1c b\u00ean li\u00ean quan.", "Gi\u1ea3i quy\u1ebft xung \u0111\u1ed9t b\u1eb1ng th\u00e1i \u0111\u1ed9 m\u1ec1m m\u1ecfng nh\u01b0ng r\u00f5 r\u00e0ng."], "situations": ["Ch\u1ecdn s\u1ed1", "B\u1ed1c th\u0103m", "Ch\u1ecdn gh\u1ebf / ph\u00f2ng", "\u0110\u01b0a ra l\u1ef1a ch\u1ecdn quan tr\u1ecdng"]}$json$::jsonb),
    (v_release_id, 'lucky_number', '3', $json${"title": "S\u00e1ng t\u1ea1o & Giao ti\u1ebfp", "message": "B\u1ea1n s\u1ebd t\u1ecfa s\u00e1ng h\u01a1n khi th\u1ec3 hi\u1ec7n \u00fd t\u01b0\u1edfng m\u1ed9t c\u00e1ch t\u1ef1 nhi\u00ean.", "meaning": "S\u1ed1 3 t\u01b0\u1ee3ng tr\u01b0ng cho s\u1ef1 bi\u1ec3u \u0111\u1ea1t, c\u1ea3m h\u1ee9ng s\u00e1ng t\u1ea1o v\u00e0 ni\u1ec1m vui k\u1ebft n\u1ed1i. N\u0103ng l\u01b0\u1ee3ng n\u00e0y gi\u00fap b\u1ea1n giao ti\u1ebfp t\u1ed1t h\u01a1n v\u00e0 lan t\u1ecfa t\u00edch c\u1ef1c.", "how_to_use": ["Chia s\u1ebb m\u1ed9t \u00fd t\u01b0\u1edfng s\u00e1ng t\u1ea1o v\u1edbi \u0111\u1ed9i nh\u00f3m ho\u1eb7c ng\u01b0\u1eddi th\u00e2n.", "Vi\u1ebft, n\u00f3i ho\u1eb7c tr\u00ecnh b\u00e0y \u0111i\u1ec1u b\u1ea1n \u0111ang \u1ea5p \u1ee7.", "D\u00e0nh th\u1eddi gian cho ho\u1ea1t \u0111\u1ed9ng nu\u00f4i d\u01b0\u1ee1ng c\u1ea3m h\u1ee9ng c\u00e1 nh\u00e2n."], "situations": ["Ch\u1ecdn s\u1ed1", "B\u1ed1c th\u0103m", "Ch\u1ecdn gh\u1ebf / ph\u00f2ng", "\u0110\u01b0a ra l\u1ef1a ch\u1ecdn quan tr\u1ecdng"]}$json$::jsonb),
    (v_release_id, 'lucky_number', '4', $json${"title": "N\u1ec1n t\u1ea3ng & K\u1ef7 lu\u1eadt", "message": "H\u00f4m nay th\u00edch h\u1ee3p \u0111\u1ec3 x\u00e2y n\u1ec1n ch\u1eafc ch\u1eafn b\u1eb1ng h\u00e0nh \u0111\u1ed9ng c\u00f3 c\u1ea5u tr\u00fac.", "meaning": "S\u1ed1 4 \u0111\u1ea1i di\u1ec7n cho s\u1ef1 \u1ed5n \u0111\u1ecbnh, t\u00ednh k\u1ef7 lu\u1eadt v\u00e0 t\u01b0 duy th\u1ef1c t\u1ebf. \u0110\u00e2y l\u00e0 n\u0103ng l\u01b0\u1ee3ng c\u1ee7a vi\u1ec7c x\u00e2y n\u1ec1n b\u1ec1n v\u1eefng v\u00e0 ho\u00e0n thi\u1ec7n c\u00f4ng vi\u1ec7c theo quy tr\u00ecnh.", "how_to_use": ["S\u1eafp x\u1ebfp l\u1ea1i k\u1ebf ho\u1ea1ch tu\u1ea7n theo m\u1ee9c \u0111\u1ed9 \u01b0u ti\u00ean r\u00f5 r\u00e0ng.", "Gi\u1ea3i quy\u1ebft c\u00e1c \u0111\u1ea7u vi\u1ec7c t\u1ed3n \u0111\u1ecdng theo checklist c\u1ee5 th\u1ec3.", "Duy tr\u00ec k\u1ef7 lu\u1eadt th\u1eddi gian cho c\u00e1c nhi\u1ec7m v\u1ee5 quan tr\u1ecdng."], "situations": ["Ch\u1ecdn s\u1ed1", "B\u1ed1c th\u0103m", "Ch\u1ecdn gh\u1ebf / ph\u00f2ng", "\u0110\u01b0a ra l\u1ef1a ch\u1ecdn quan tr\u1ecdng"]}$json$::jsonb),
    (v_release_id, 'lucky_number', '5', $json${"title": "T\u1ef1 do & Thay \u0111\u1ed5i", "message": "M\u1ed9t thay \u0111\u1ed5i nh\u1ecf \u0111\u00fang l\u00fac c\u00f3 th\u1ec3 m\u1edf ra c\u01a1 h\u1ed9i l\u1edbn.", "meaning": "S\u1ed1 5 t\u01b0\u1ee3ng tr\u01b0ng cho s\u1ef1 linh ho\u1ea1t, tr\u1ea3i nghi\u1ec7m m\u1edbi v\u00e0 tinh th\u1ea7n kh\u00e1m ph\u00e1. N\u0103ng l\u01b0\u1ee3ng n\u00e0y gi\u00fap b\u1ea1n th\u00edch nghi nhanh v\u00e0 m\u1edf r\u1ed9ng c\u01a1 h\u1ed9i.", "how_to_use": ["Th\u1eed m\u1ed9t c\u00e1ch l\u00e0m m\u1edbi cho c\u00f4ng vi\u1ec7c quen thu\u1ed9c.", "M\u1edf r\u1ed9ng k\u1ebft n\u1ed1i v\u1edbi m\u1ed9t ng\u01b0\u1eddi ho\u1eb7c m\u00f4i tr\u01b0\u1eddng m\u1edbi.", "Linh ho\u1ea1t \u0111i\u1ec1u ch\u1ec9nh k\u1ebf ho\u1ea1ch khi xu\u1ea5t hi\u1ec7n c\u01a1 h\u1ed9i ph\u00f9 h\u1ee3p."], "situations": ["Ch\u1ecdn s\u1ed1", "B\u1ed1c th\u0103m", "Ch\u1ecdn gh\u1ebf / ph\u00f2ng", "\u0110\u01b0a ra l\u1ef1a ch\u1ecdn quan tr\u1ecdng"]}$json$::jsonb),
    (v_release_id, 'lucky_number', '6', $json${"title": "Tr\u00e1ch nhi\u1ec7m & Ch\u0103m s\u00f3c", "message": "N\u0103ng l\u01b0\u1ee3ng h\u00f4m nay nh\u1ea5n m\u1ea1nh s\u1ef1 quan t\u00e2m v\u00e0 c\u00e2n b\u1eb1ng trong quan h\u1ec7.", "meaning": "S\u1ed1 6 \u0111\u1ea1i di\u1ec7n cho s\u1ef1 y\u00eau th\u01b0\u01a1ng, tr\u00e1ch nhi\u1ec7m v\u00e0 kh\u1ea3 n\u0103ng ch\u0103m s\u00f3c ng\u01b0\u1eddi kh\u00e1c. \u0110\u00e2y l\u00e0 n\u0103ng l\u01b0\u1ee3ng c\u1ee7a gia \u0111\u00ecnh, c\u1ed9ng \u0111\u1ed3ng v\u00e0 s\u1ef1 c\u00e2n b\u1eb1ng c\u1ea3m x\u00fac.", "how_to_use": ["D\u00e0nh th\u1eddi gian ch\u1ea5t l\u01b0\u1ee3ng cho ng\u01b0\u1eddi th\u00e2n ho\u1eb7c c\u1ed9ng s\u1ef1 quan tr\u1ecdng.", "Gi\u00fap \u0111\u1ee1 m\u1ed9t ng\u01b0\u1eddi \u0111ang c\u1ea7n h\u1ed7 tr\u1ee3 th\u1ef1c t\u1ebf.", "Thi\u1ebft l\u1eadp ranh gi\u1edbi l\u00e0nh m\u1ea1nh \u0111\u1ec3 ch\u0103m s\u00f3c c\u1ea3 b\u1ea3n th\u00e2n l\u1eabn ng\u01b0\u1eddi kh\u00e1c."], "situations": ["Ch\u1ecdn s\u1ed1", "B\u1ed1c th\u0103m", "Ch\u1ecdn gh\u1ebf / ph\u00f2ng", "\u0110\u01b0a ra l\u1ef1a ch\u1ecdn quan tr\u1ecdng"]}$json$::jsonb),
    (v_release_id, 'lucky_number', '7', $json${"title": "S\u1ed1 c\u1ee7a Tr\u00ed tu\u1ec7", "message": "Con s\u1ed1 n\u00e0y g\u1ee3i \u00fd b\u1ea1n tin v\u00e0o tr\u1ef1c gi\u00e1c v\u00e0 suy ngh\u0129 s\u00e2u h\u01a1n tr\u01b0\u1edbc khi h\u00e0nh \u0111\u1ed9ng.", "meaning": "S\u1ed1 7 \u0111\u1ea1i di\u1ec7n cho tr\u00ed tu\u1ec7, s\u1ef1 suy ng\u1eabm v\u00e0 k\u1ebft n\u1ed1i n\u1ed9i t\u00e2m. Trong numerology, n\u00f3 th\u01b0\u1eddng li\u00ean quan \u0111\u1ebfn vi\u1ec7c t\u00ecm ki\u1ebfm c\u00e2u tr\u1ea3 l\u1eddi s\u00e2u s\u1eafc v\u00e0 ph\u00e1t tri\u1ec3n nh\u1eadn th\u1ee9c.", "how_to_use": ["Tin v\u00e0o tr\u1ef1c gi\u00e1c khi c\u1ea7n ch\u1ecdn gi\u1eefa nhi\u1ec1u ph\u01b0\u01a1ng \u00e1n.", "\u01afu ti\u00ean c\u00e1c l\u1ef1a ch\u1ecdn c\u00f3 li\u00ean quan \u0111\u1ebfn s\u1ed1 7.", "D\u00e0nh th\u1eddi gian suy ngh\u0129 tr\u01b0\u1edbc khi \u0111\u01b0a ra quy\u1ebft \u0111\u1ecbnh."], "situations": ["Ch\u1ecdn s\u1ed1", "B\u1ed1c th\u0103m", "Ch\u1ecdn gh\u1ebf / ph\u00f2ng", "\u0110\u01b0a ra l\u1ef1a ch\u1ecdn quan tr\u1ecdng"]}$json$::jsonb),
    (v_release_id, 'lucky_number', '8', $json${"title": "Quy\u1ec1n l\u1ef1c & Th\u00e0nh c\u00f4ng", "message": "H\u00f4m nay thu\u1eadn l\u1ee3i \u0111\u1ec3 t\u1eadp trung v\u00e0o k\u1ebft qu\u1ea3 v\u00e0 th\u00e0nh t\u1ef1u c\u1ee5 th\u1ec3.", "meaning": "S\u1ed1 8 \u0111\u1ea1i di\u1ec7n cho n\u0103ng l\u01b0\u1ee3ng th\u00e0nh t\u1ef1u, hi\u1ec7u su\u1ea5t v\u00e0 kh\u1ea3 n\u0103ng qu\u1ea3n tr\u1ecb ngu\u1ed3n l\u1ef1c. \u0110\u00e2y l\u00e0 con s\u1ed1 c\u1ee7a m\u1ee5c ti\u00eau r\u00f5 r\u00e0ng v\u00e0 k\u1ebft qu\u1ea3 h\u1eefu h\u00ecnh.", "how_to_use": ["\u0110\u1eb7t m\u1ee5c ti\u00eau \u0111o l\u01b0\u1eddng \u0111\u01b0\u1ee3c v\u00e0 ki\u1ec3m tra ti\u1ebfn \u0111\u1ed9 v\u00e0o cu\u1ed1i ng\u00e0y.", "\u01afu ti\u00ean nhi\u1ec7m v\u1ee5 t\u1ea1o t\u00e1c \u0111\u1ed9ng l\u1edbn \u0111\u1ebfn c\u00f4ng vi\u1ec7c ho\u1eb7c t\u00e0i ch\u00ednh.", "Th\u1ef1c hi\u1ec7n m\u1ed9t quy\u1ebft \u0111\u1ecbnh d\u1ee9t kho\u00e1t \u0111\u1ec3 ti\u1ebfn g\u1ea7n m\u1ee5c ti\u00eau d\u00e0i h\u1ea1n."], "situations": ["Ch\u1ecdn s\u1ed1", "B\u1ed1c th\u0103m", "Ch\u1ecdn gh\u1ebf / ph\u00f2ng", "\u0110\u01b0a ra l\u1ef1a ch\u1ecdn quan tr\u1ecdng"]}$json$::jsonb),
    (v_release_id, 'lucky_number', '9', $json${"title": "Ho\u00e0n th\u00e0nh & T\u1eeb bi", "message": "\u0110\u00e2y l\u00e0 th\u1eddi \u0111i\u1ec3m ph\u00f9 h\u1ee3p \u0111\u1ec3 kh\u00e9p l\u1ea1i \u0111i\u1ec1u c\u0169 v\u00e0 m\u1edf l\u00f2ng cho \u0111i\u1ec1u m\u1edbi.", "meaning": "S\u1ed1 9 t\u01b0\u1ee3ng tr\u01b0ng cho s\u1ef1 ho\u00e0n t\u1ea5t, l\u00f2ng nh\u00e2n \u00e1i v\u00e0 kh\u1ea3 n\u0103ng bu\u00f4ng b\u1ecf \u0111i\u1ec1u kh\u00f4ng c\u00f2n ph\u00f9 h\u1ee3p. N\u0103ng l\u01b0\u1ee3ng n\u00e0y gi\u00fap b\u1ea1n chuy\u1ec3n sang chu k\u1ef3 m\u1edbi nh\u1eb9 nh\u00e0ng h\u01a1n.", "how_to_use": ["Ho\u00e0n t\u1ea5t m\u1ed9t vi\u1ec7c dang d\u1edf \u0111\u00e3 k\u00e9o d\u00e0i nhi\u1ec1u ng\u00e0y.", "Bu\u00f4ng b\u1ecf m\u1ed9t th\u00f3i quen ho\u1eb7c ni\u1ec1m tin kh\u00f4ng c\u00f2n ph\u00f9 h\u1ee3p.", "L\u00e0m m\u1ed9t h\u00e0nh \u0111\u1ed9ng t\u1eed t\u1ebf cho c\u1ed9ng \u0111\u1ed3ng ho\u1eb7c ng\u01b0\u1eddi xung quanh."], "situations": ["Ch\u1ecdn s\u1ed1", "B\u1ed1c th\u0103m", "Ch\u1ecdn gh\u1ebf / ph\u00f2ng", "\u0110\u01b0a ra l\u1ef1a ch\u1ecdn quan tr\u1ecdng"]}$json$::jsonb),
    (v_release_id, 'angel_number', '111', $json${"title": "Bi\u1ec3u hi\u1ec7n & Kh\u1edfi \u0111\u1ea7u m\u1edbi", "guidance": ["T\u1eadp trung v\u00e0o \u0111i\u1ec1u b\u1ea1n mu\u1ed1n, kh\u00f4ng ph\u1ea3i \u0111i\u1ec1u b\u1ea1n s\u1ee3 h\u00e3i", "\u0110\u00e2y l\u00e0 th\u1eddi \u0111i\u1ec3m t\u1ed1t \u0111\u1ec3 b\u1eaft \u0111\u1ea7u d\u1ef1 \u00e1n m\u1edbi", "H\u00e3y gi\u1eef suy ngh\u0129 t\u00edch c\u1ef1c v\u00e0 l\u1ea1c quan"], "core_meanings": ["Kh\u1edfi \u0111\u1ea7u m\u1edbi v\u00e0 ch\u1ee7 \u0111\u1ed9ng h\u00e0nh \u0111\u1ed9ng.", "S\u1ee9c m\u1ea1nh \u00fd \u0111\u1ecbnh \u0111\u01b0\u1ee3c khu\u1ebfch \u0111\u1ea1i.", "T\u01b0 duy t\u00edch c\u1ef1c t\u1ea1o n\u1ec1n cho k\u1ebft qu\u1ea3 t\u1ed1t."], "universe_messages": ["V\u0169 tr\u1ee5 \u0111ang ph\u1ea3n h\u1ed3i r\u1ea5t nhanh v\u1edbi \u0111i\u1ec1u b\u1ea1n t\u1eadp trung.", "H\u00e3y \u0111\u1eb7t m\u1ee5c ti\u00eau c\u1ee5 th\u1ec3 ngay l\u00fac n\u00e0y.", "M\u1ecdi kh\u1edfi \u0111\u1ea7u \u0111\u1ec1u thu\u1eadn khi b\u1ea1n d\u00e1m b\u01b0\u1edbc tr\u01b0\u1edbc."]}$json$::jsonb),
    (v_release_id, 'angel_number', '222', $json${"title": "C\u00e2n b\u1eb1ng & H\u00e0i h\u00f2a", "guidance": ["M\u1ecdi th\u1ee9 \u0111ang di\u1ec5n ra \u0111\u00fang th\u1eddi \u0111i\u1ec3m", "H\u00e3y ki\u00ean nh\u1eabn v\u00e0 tin t\u01b0\u1edfng v\u00e0o k\u1ebf ho\u1ea1ch c\u1ee7a v\u0169 tr\u1ee5", "T\u1eadp trung v\u00e0o vi\u1ec7c t\u1ea1o h\u00f2a h\u1ee3p trong c\u00e1c m\u1ed1i quan h\u1ec7"], "core_meanings": ["C\u00e2n b\u1eb1ng n\u1ed9i t\u00e2m v\u00e0 c\u00e1c m\u1ed1i quan h\u1ec7.", "Tin t\u01b0\u1edfng ti\u1ebfn tr\u00ecnh \u0111ang di\u1ec5n ra \u0111\u00fang nh\u1ecbp.", "Ki\u00ean nh\u1eabn l\u00e0 ch\u00eca kh\u00f3a \u0111\u1ec3 m\u1ecdi th\u1ee9 ch\u00edn mu\u1ed3i."], "universe_messages": ["M\u1ecdi th\u1ee9 \u0111ang \u0111\u01b0\u1ee3c s\u1eafp x\u1ebfp \u0111\u00fang th\u1eddi \u0111i\u1ec3m.", "Gi\u1eef b\u00ecnh t\u0129nh \u0111\u1ec3 nh\u00ecn th\u1ea5y t\u00edn hi\u1ec7u r\u00f5 r\u00e0ng h\u01a1n.", "S\u1ef1 h\u00e0i h\u00f2a s\u1ebd \u0111\u1ebfn khi b\u1ea1n ch\u1ecdn h\u1ee3p t\u00e1c thay v\u00ec \u0111\u1ed1i kh\u00e1ng."]}$json$::jsonb),
    (v_release_id, 'angel_number', '333', $json${"title": "S\u1ef1 b\u1ea3o v\u1ec7 & H\u1ed7 tr\u1ee3", "guidance": ["B\u1ea1n kh\u00f4ng h\u1ec1 c\u00f4 \u0111\u01a1n tr\u00ean con \u0111\u01b0\u1eddng n\u00e0y", "H\u00e3y l\u1eafng nghe tr\u1ef1c gi\u00e1c v\u00e0 s\u1ef1 h\u01b0\u1edbng d\u1eabn n\u1ed9i t\u00e2m", "\u0110\u00e2y l\u00e0 l\u00fac \u0111\u1ec3 ph\u00e1t tri\u1ec3n kh\u1ea3 n\u0103ng s\u00e1ng t\u1ea1o c\u1ee7a b\u1ea1n"], "core_meanings": ["B\u1ea1n \u0111ang \u0111\u01b0\u1ee3c h\u1ed7 tr\u1ee3 tr\u00ean h\u00e0nh tr\u00ecnh hi\u1ec7n t\u1ea1i.", "S\u00e1ng t\u1ea1o v\u00e0 bi\u1ec3u \u0111\u1ea1t n\u00ean \u0111\u01b0\u1ee3c \u01b0u ti\u00ean.", "K\u1ebft n\u1ed1i tr\u1ef1c gi\u00e1c \u0111\u1ec3 nh\u1eadn ch\u1ec9 d\u1eabn r\u00f5 h\u01a1n."], "universe_messages": ["B\u1ea1n kh\u00f4ng \u0111\u01a1n \u0111\u1ed9c, lu\u00f4n c\u00f3 s\u1ef1 tr\u1ee3 gi\u00fap tinh th\u1ea7n b\u00ean c\u1ea1nh.", "H\u00e3y n\u00f3i ra \u00fd t\u01b0\u1edfng c\u1ee7a m\u00ecnh v\u1edbi s\u1ef1 t\u1ef1 tin.", "Ngu\u1ed3n c\u1ea3m h\u1ee9ng \u0111ang \u0111\u1ebfn, \u0111\u1eebng tr\u00ec ho\u00e3n vi\u1ec7c t\u1ea1o ra gi\u00e1 tr\u1ecb."]}$json$::jsonb),
    (v_release_id, 'angel_number', '444', $json${"title": "N\u1ec1n t\u1ea3ng v\u1eefng ch\u1eafc", "guidance": ["Ti\u1ebfp t\u1ee5c l\u00e0m vi\u1ec7c ch\u0103m ch\u1ec9, b\u1ea1n \u0111ang \u0111i \u0111\u00fang h\u01b0\u1edbng", "C\u00e1c thi\u00ean th\u1ea7n \u0111ang \u1edf b\u00ean b\u1ea1n v\u00e0 h\u1ed7 tr\u1ee3 b\u1ea1n", "H\u00e3y t\u1eadp trung v\u00e0o m\u1ee5c ti\u00eau d\u00e0i h\u1ea1n"], "core_meanings": ["N\u1ec1n t\u1ea3ng b\u1ea1n x\u00e2y \u0111ang ng\u00e0y c\u00e0ng v\u1eefng ch\u1eafc.", "K\u1ef7 lu\u1eadt v\u00e0 nh\u1ea5t qu\u00e1n s\u1ebd \u0111em l\u1ea1i th\u00e0nh qu\u1ea3.", "S\u1ef1 b\u1ea3o h\u1ed9 \u0111ang \u0111\u1ed3ng h\u00e0nh c\u00f9ng n\u1ed7 l\u1ef1c c\u1ee7a b\u1ea1n."], "universe_messages": ["V\u0169 tr\u1ee5 x\u00e1c nh\u1eadn b\u1ea1n \u0111ang \u0111i \u0111\u00fang h\u01b0\u1edbng.", "Ti\u1ebfp t\u1ee5c t\u1eebng b\u01b0\u1edbc nh\u1ecf nh\u01b0ng ch\u1eafc ch\u1eafn m\u1ed7i ng\u00e0y.", "S\u1ef1 b\u1ec1n b\u1ec9 h\u00f4m nay l\u00e0 n\u1ec1n cho k\u1ebft qu\u1ea3 l\u1edbn mai sau."]}$json$::jsonb),
    (v_release_id, 'angel_number', '555', $json${"title": "Thay \u0111\u1ed5i l\u1edbn", "guidance": ["\u0110\u00f3n nh\u1eadn s\u1ef1 thay \u0111\u1ed5i v\u1edbi t\u00e2m th\u1ebf c\u1edfi m\u1edf", "Bu\u00f4ng b\u1ecf nh\u1eefng g\u00ec kh\u00f4ng c\u00f2n ph\u1ee5c v\u1ee5 b\u1ea1n", "Chu\u1ea9n b\u1ecb cho c\u01a1 h\u1ed9i m\u1edbi v\u00e0 tr\u1ea3i nghi\u1ec7m m\u1edbi"], "core_meanings": ["M\u1ed9t chu k\u1ef3 thay \u0111\u1ed5i l\u1edbn \u0111ang m\u1edf ra.", "Linh ho\u1ea1t gi\u00fap b\u1ea1n th\u00edch nghi nhanh h\u01a1n.", "Bu\u00f4ng b\u1ecf c\u0169 \u0111\u1ec3 \u0111\u00f3n c\u01a1 h\u1ed9i m\u1edbi."], "universe_messages": ["\u0110\u00e3 \u0111\u1ebfn l\u00fac ch\u1ea5p nh\u1eadn thay \u0111\u1ed5i nh\u01b0 m\u1ed9t m\u00f3n qu\u00e0 ph\u00e1t tri\u1ec3n.", "C\u01a1 h\u1ed9i m\u1edbi xu\u1ea5t hi\u1ec7n khi b\u1ea1n d\u00e1m r\u1eddi v\u00f9ng quen thu\u1ed9c.", "H\u00e3y ch\u1ecdn \u0111i\u1ec1u ph\u00f9 h\u1ee3p v\u1edbi phi\u00ean b\u1ea3n m\u1edbi c\u1ee7a b\u1ea1n."]}$json$::jsonb),
