    (v_release_id, 'number_library', '33', $json${"title": "Ch\u1eefa l\u00e0nh to\u00e0n di\u1ec7n", "description": "Master number c\u1ee7a t\u00ecnh y\u00eau v\u00f4 \u0111i\u1ec1u ki\u1ec7n v\u00e0 ph\u1ee5ng s\u1ef1.", "keywords": ["Ch\u1eefa l\u00e0nh", "Gi\u1ea3ng d\u1ea1y", "Y\u00eau th\u01b0\u01a1ng"], "symbolism": "Bi\u1ec3u t\u01b0\u1ee3ng c\u1ee7a Ch\u1eefa l\u00e0nh to\u00e0n di\u1ec7n, ph\u1ea3n \u00e1nh tr\u01b0\u1eddng n\u0103ng l\u01b0\u1ee3ng \u0111\u1eb7c tr\u01b0ng v\u00e0 b\u00e0i h\u1ecdc c\u1ed1t l\u00f5i c\u1ee7a con s\u1ed1 n\u00e0y."}$json$::jsonb),
    (v_release_id, 'todaypersonalnumber', '1', $json${"quote": "H\u00f4m nay l\u00e0 l\u00fac b\u1ea1n ch\u1ee7 \u0111\u1ed9ng m\u1edf l\u1ed1i v\u00e0 n\u00f3i r\u00f5 \u0111i\u1ec1u m\u00ecnh mu\u1ed1n.", "daily_rhythm": "Kh\u1edfi \u0111\u1ed9ng - D\u1eabn d\u1eaft", "detail": ["Ng\u00e0y c\u00e1 nh\u00e2n 1 mang n\u0103ng l\u01b0\u1ee3ng ti\u00ean phong, ph\u00f9 h\u1ee3p \u0111\u1ec3 b\u1eaft \u0111\u1ea7u vi\u1ec7c m\u1edbi v\u00e0 t\u1ef1 \u0111\u01b0a ra quy\u1ebft \u0111\u1ecbnh.", "B\u1ea1n s\u1ebd c\u00f3 xu h\u01b0\u1edbng h\u00e0nh \u0111\u1ed9ng nhanh, r\u00f5 m\u1ee5c ti\u00eau v\u00e0 mu\u1ed1n t\u1ef1 ch\u1ecbu tr\u00e1ch nhi\u1ec7m cho k\u1ebft qu\u1ea3.", "Khi gi\u1eef \u0111\u01b0\u1ee3c s\u1ef1 t\u1eadp trung, n\u0103ng l\u01b0\u1ee3ng s\u1ed1 1 gi\u00fap b\u1ea1n m\u1edf \u0111\u01b0\u1eddng cho c\u1ea3 chu k\u1ef3 m\u1edbi ph\u00eda tr\u01b0\u1edbc."], "hint_actions": ["X\u00e1c \u0111\u1ecbnh 1 vi\u1ec7c quan tr\u1ecdng nh\u1ea5t v\u00e0 ho\u00e0n th\u00e0nh b\u01b0\u1edbc \u0111\u1ea7u ti\u00ean ngay h\u00f4m nay.", "Ch\u1ee7 \u0111\u1ed9ng \u0111\u1ec1 xu\u1ea5t \u00fd t\u01b0\u1edfng thay v\u00ec ch\u1edd ng\u01b0\u1eddi kh\u00e1c d\u1eabn d\u1eaft.", "Gi\u1eef c\u00e1ch n\u00f3i ng\u1eafn g\u1ecdn, r\u00f5 r\u00e0ng khi trao \u0111\u1ed5i c\u00f4ng vi\u1ec7c.", "Tr\u00e1nh \u00f4m qu\u00e1 nhi\u1ec1u vi\u1ec7c c\u00f9ng l\u00fac \u0111\u1ec3 kh\u00f4ng b\u1ecb ph\u00e2n t\u00e1n n\u0103ng l\u01b0\u1ee3ng."], "should_do": ["X\u00e1c \u0111\u1ecbnh 1 vi\u1ec7c quan tr\u1ecdng nh\u1ea5t v\u00e0 ho\u00e0n th\u00e0nh b\u01b0\u1edbc \u0111\u1ea7u ti\u00ean ngay h\u00f4m nay.", "Ch\u1ee7 \u0111\u1ed9ng \u0111\u1ec1 xu\u1ea5t \u00fd t\u01b0\u1edfng thay v\u00ec ch\u1edd ng\u01b0\u1eddi kh\u00e1c d\u1eabn d\u1eaft."], "should_avoid": ["Tr\u00e1nh \u00f4m qu\u00e1 nhi\u1ec1u vi\u1ec7c c\u00f9ng l\u00fac \u0111\u1ec3 kh\u00f4ng b\u1ecb ph\u00e2n t\u00e1n n\u0103ng l\u01b0\u1ee3ng."]}$json$::jsonb),
    (v_release_id, 'todaypersonalnumber', '2', $json${"quote": "Nh\u1eb9 l\u1ea1i m\u1ed9t nh\u1ecbp \u0111\u1ec3 l\u1eafng nghe, h\u00f2a h\u1ee3p v\u00e0 k\u1ebft n\u1ed1i s\u00e2u h\u01a1n.", "daily_rhythm": "L\u1eafng nghe - Ph\u1ed1i h\u1ee3p", "detail": ["Ng\u00e0y c\u00e1 nh\u00e2n 2 nh\u1ea5n m\u1ea1nh s\u1ef1 h\u1ee3p t\u00e1c, c\u1ea3m x\u00fac tinh t\u1ebf v\u00e0 kh\u1ea3 n\u0103ng ngo\u1ea1i giao.", "B\u1ea1n d\u1ec5 th\u00e0nh c\u00f4ng h\u01a1n khi l\u00e0m vi\u1ec7c c\u00f9ng ng\u01b0\u1eddi kh\u00e1c thay v\u00ec c\u1ed1 g\u1eafng \u0111i m\u1ed9t m\u00ecnh.", "S\u1ef1 ki\u00ean nh\u1eabn h\u00f4m nay s\u1ebd gi\u00fap c\u00e1c m\u1ed1i quan h\u1ec7 quan tr\u1ecdng tr\u1edf n\u00ean b\u1ec1n v\u1eefng h\u01a1n."], "hint_actions": ["D\u00e0nh th\u1eddi gian l\u1eafng nghe tr\u01b0\u1edbc khi ph\u1ea3n h\u1ed3i trong cu\u1ed9c tr\u00f2 chuy\u1ec7n quan tr\u1ecdng.", "\u01afu ti\u00ean l\u00e0m vi\u1ec7c nh\u00f3m v\u00e0 \u0111\u1ed3ng b\u1ed9 k\u1ef3 v\u1ecdng gi\u1eefa c\u00e1c b\u00ean.", "X\u1eed l\u00fd m\u00e2u thu\u1eabn b\u1eb1ng th\u00e1i \u0111\u1ed9 m\u1ec1m m\u1ecfng nh\u01b0ng c\u00f3 ranh gi\u1edbi r\u00f5 r\u00e0ng.", "Tr\u00e1nh quy\u1ebft \u0111\u1ecbnh n\u00f3ng v\u1ed9i khi c\u1ea3m x\u00fac \u0111ang dao \u0111\u1ed9ng."], "should_do": ["D\u00e0nh th\u1eddi gian l\u1eafng nghe tr\u01b0\u1edbc khi ph\u1ea3n h\u1ed3i trong cu\u1ed9c tr\u00f2 chuy\u1ec7n quan tr\u1ecdng.", "\u01afu ti\u00ean l\u00e0m vi\u1ec7c nh\u00f3m v\u00e0 \u0111\u1ed3ng b\u1ed9 k\u1ef3 v\u1ecdng gi\u1eefa c\u00e1c b\u00ean."], "should_avoid": ["Tr\u00e1nh quy\u1ebft \u0111\u1ecbnh n\u00f3ng v\u1ed9i khi c\u1ea3m x\u00fac \u0111ang dao \u0111\u1ed9ng."]}$json$::jsonb),
    (v_release_id, 'todaypersonalnumber', '3', $json${"quote": "N\u0103ng l\u01b0\u1ee3ng h\u00f4m nay m\u1edf ra c\u1ea3m h\u1ee9ng s\u00e1ng t\u1ea1o v\u00e0 s\u1ef1 bi\u1ec3u \u0111\u1ea1t t\u1ef1 nhi\u00ean.", "daily_rhythm": "M\u1edf r\u1ed9ng - K\u1ebft n\u1ed1i", "detail": ["Ng\u00e0y c\u00e1 nh\u00e2n 3 thu\u1eadn cho giao ti\u1ebfp, chia s\u1ebb \u00fd t\u01b0\u1edfng v\u00e0 lan t\u1ecfa tinh th\u1ea7n t\u00edch c\u1ef1c.", "B\u1ea1n c\u00f3 th\u1ec3 th\u1ea5y m\u00ecnh d\u1ec5 n\u00f3i ra suy ngh\u0129 h\u01a1n v\u00e0 thu h\u00fat s\u1ef1 ch\u00fa \u00fd t\u1ef1 nhi\u00ean.", "N\u1ebfu bi\u1ebft gi\u1eef nh\u1ecbp t\u1eadp trung, c\u1ea3m h\u1ee9ng trong ng\u00e0y s\u1ebd chuy\u1ec3n th\u00e0nh k\u1ebft qu\u1ea3 r\u00f5 r\u00e0ng."], "hint_actions": ["\u01afu ti\u00ean c\u00e1c c\u00f4ng vi\u1ec7c c\u1ea7n tr\u00ecnh b\u00e0y, vi\u1ebft l\u00e1ch ho\u1eb7c s\u00e1ng t\u1ea1o n\u1ed9i dung.", "Chia s\u1ebb m\u1ed9t \u00fd t\u01b0\u1edfng m\u1edbi v\u1edbi ng\u01b0\u1eddi c\u00f3 th\u1ec3 h\u1ed7 tr\u1ee3 b\u1ea1n ph\u00e1t tri\u1ec3n n\u00f3.", "Gi\u1eef l\u1ecbch l\u00e0m vi\u1ec7c theo t\u1eebng khung th\u1eddi gian \u0111\u1ec3 tr\u00e1nh lan man.", "K\u1ebft th\u00fac ng\u00e0y b\u1eb1ng 1 ghi ch\u00fa ng\u1eafn v\u1ec1 \u0111i\u1ec1u truy\u1ec1n c\u1ea3m h\u1ee9ng cho b\u1ea1n."], "should_do": ["\u01afu ti\u00ean c\u00e1c c\u00f4ng vi\u1ec7c c\u1ea7n tr\u00ecnh b\u00e0y, vi\u1ebft l\u00e1ch ho\u1eb7c s\u00e1ng t\u1ea1o n\u1ed9i dung.", "Chia s\u1ebb m\u1ed9t \u00fd t\u01b0\u1edfng m\u1edbi v\u1edbi ng\u01b0\u1eddi c\u00f3 th\u1ec3 h\u1ed7 tr\u1ee3 b\u1ea1n ph\u00e1t tri\u1ec3n n\u00f3."], "should_avoid": ["Tr\u00e1nh quy\u1ebft \u0111\u1ecbnh v\u1ed9i khi ch\u01b0a \u0111\u1ee7 d\u1eef li\u1ec7u."]}$json$::jsonb),
    (v_release_id, 'todaypersonalnumber', '4', $json${"quote": "H\u00f4m nay ph\u00f9 h\u1ee3p \u0111\u1ec3 x\u00e2y n\u1ec1n v\u1eefng ch\u1eafc b\u1eb1ng k\u1ef7 lu\u1eadt v\u00e0 tr\u1eadt t\u1ef1.", "daily_rhythm": "\u1ed4n \u0111\u1ecbnh - X\u00e2y n\u1ec1n", "detail": ["Ng\u00e0y c\u00e1 nh\u00e2n 4 l\u00e0 nh\u1ecbp n\u0103ng l\u01b0\u1ee3ng c\u1ee7a c\u1ea5u tr\u00fac, tr\u00e1ch nhi\u1ec7m v\u00e0 t\u00ednh th\u1ef1c t\u1ebf.", "B\u1ea1n s\u1ebd l\u00e0m vi\u1ec7c hi\u1ec7u qu\u1ea3 h\u01a1n khi c\u00f3 k\u1ebf ho\u1ea1ch r\u00f5 r\u00e0ng v\u00e0 th\u1ee9 t\u1ef1 \u01b0u ti\u00ean c\u1ee5 th\u1ec3.", "Th\u00e0nh qu\u1ea3 h\u00f4m nay \u0111\u1ebfn t\u1eeb s\u1ef1 \u0111\u1ec1u \u0111\u1eb7n, kh\u00f4ng ph\u1ea3i t\u1ed1c \u0111\u1ed9 b\u00f9ng n\u1ed5."], "hint_actions": ["L\u1eadp danh s\u00e1ch vi\u1ec7c theo m\u1ee9c \u0111\u1ed9 quan tr\u1ecdng v\u00e0 x\u1eed l\u00fd tu\u1ea7n t\u1ef1.", "D\u1ecdn g\u1ecdn kh\u00f4ng gian l\u00e0m vi\u1ec7c \u0111\u1ec3 t\u0103ng kh\u1ea3 n\u0103ng t\u1eadp trung.", "Kh\u00f3a th\u1eddi gian cho c\u00e1c nhi\u1ec7m v\u1ee5 \u0111\u00f2i h\u1ecfi chi\u1ec1u s\u00e2u.", "Tr\u00e1nh tr\u00ec ho\u00e3n c\u00e1c vi\u1ec7c nh\u1ecf v\u00ec ch\u00fang d\u1ec5 t\u1ea1o t\u1ed3n \u0111\u1ecdng."], "should_do": ["L\u1eadp danh s\u00e1ch vi\u1ec7c theo m\u1ee9c \u0111\u1ed9 quan tr\u1ecdng v\u00e0 x\u1eed l\u00fd tu\u1ea7n t\u1ef1.", "D\u1ecdn g\u1ecdn kh\u00f4ng gian l\u00e0m vi\u1ec7c \u0111\u1ec3 t\u0103ng kh\u1ea3 n\u0103ng t\u1eadp trung."], "should_avoid": ["Tr\u00e1nh tr\u00ec ho\u00e3n c\u00e1c vi\u1ec7c nh\u1ecf v\u00ec ch\u00fang d\u1ec5 t\u1ea1o t\u1ed3n \u0111\u1ecdng."]}$json$::jsonb),
    (v_release_id, 'todaypersonalnumber', '5', $json${"quote": "M\u1ed9t thay \u0111\u1ed5i \u0111\u00fang l\u00fac h\u00f4m nay c\u00f3 th\u1ec3 m\u1edf ra c\u01a1 h\u1ed9i m\u1edbi.", "daily_rhythm": "Linh ho\u1ea1t - Kh\u00e1m ph\u00e1", "detail": ["Ng\u00e0y c\u00e1 nh\u00e2n 5 mang n\u0103ng l\u01b0\u1ee3ng d\u1ecbch chuy\u1ec3n, t\u1ef1 do v\u00e0 kh\u1ea3 n\u0103ng th\u00edch nghi nhanh.", "B\u1ea1n d\u1ec5 g\u1eb7p c\u00e1c t\u00ecnh hu\u1ed1ng b\u1ea5t ng\u1edd ho\u1eb7c l\u1eddi m\u1eddi m\u1edbi c\u1ea7n quy\u1ebft \u0111\u1ecbnh nhanh.", "S\u1ef1 c\u1edfi m\u1edf s\u1ebd gi\u00fap b\u1ea1n t\u1eadn d\u1ee5ng c\u01a1 h\u1ed9i, nh\u01b0ng v\u1eabn c\u1ea7n \u0111i\u1ec3m t\u1ef1a r\u00f5 r\u00e0ng."], "hint_actions": ["Th\u1eed m\u1ed9t c\u00e1ch l\u00e0m m\u1edbi cho c\u00f4ng vi\u1ec7c quen thu\u1ed9c.", "M\u1edf r\u1ed9ng k\u1ebft n\u1ed1i v\u1edbi ng\u01b0\u1eddi ho\u1eb7c m\u00f4i tr\u01b0\u1eddng m\u1edbi.", "Gi\u1eef 1-2 \u01b0u ti\u00ean c\u1ed1t l\u00f5i \u0111\u1ec3 kh\u00f4ng b\u1ecb cu\u1ed1n theo qu\u00e1 nhi\u1ec1u h\u01b0\u1edbng.", "Tr\u00e1nh cam k\u1ebft v\u1ed9i khi ch\u01b0a \u0111\u00e1nh gi\u00e1 \u0111\u1ee7 th\u00f4ng tin."], "should_do": ["Th\u1eed m\u1ed9t c\u00e1ch l\u00e0m m\u1edbi cho c\u00f4ng vi\u1ec7c quen thu\u1ed9c.", "M\u1edf r\u1ed9ng k\u1ebft n\u1ed1i v\u1edbi ng\u01b0\u1eddi ho\u1eb7c m\u00f4i tr\u01b0\u1eddng m\u1edbi."], "should_avoid": ["Tr\u00e1nh cam k\u1ebft v\u1ed9i khi ch\u01b0a \u0111\u00e1nh gi\u00e1 \u0111\u1ee7 th\u00f4ng tin."]}$json$::jsonb),
    (v_release_id, 'todaypersonalnumber', '6', $json${"quote": "H\u00f4m nay m\u1eddi b\u1ea1n c\u00e2n b\u1eb1ng gi\u1eefa ch\u0103m s\u00f3c ng\u01b0\u1eddi kh\u00e1c v\u00e0 ch\u0103m s\u00f3c ch\u00ednh m\u00ecnh.", "daily_rhythm": "Nu\u00f4i d\u01b0\u1ee1ng - C\u00e2n b\u1eb1ng", "detail": ["Ng\u00e0y c\u00e1 nh\u00e2n 6 t\u1eadp trung v\u00e0o t\u00ecnh c\u1ea3m, tr\u00e1ch nhi\u1ec7m v\u00e0 s\u1ef1 g\u1eafn k\u1ebft gia \u0111\u00ecnh ho\u1eb7c c\u1ed9ng \u0111\u1ed3ng.", "B\u1ea1n c\u00f3 xu h\u01b0\u1edbng quan t\u00e2m nhi\u1ec1u h\u01a1n \u0111\u1ebfn s\u1ef1 h\u00e0i h\u00f2a trong c\u00e1c m\u1ed1i quan h\u1ec7 g\u1ea7n.", "Khi gi\u1eef ranh gi\u1edbi l\u00e0nh m\u1ea1nh, n\u0103ng l\u01b0\u1ee3ng s\u1ed1 6 gi\u00fap b\u1ea1n cho \u0111i m\u00e0 kh\u00f4ng ki\u1ec7t s\u1ee9c."], "hint_actions": ["D\u00e0nh th\u1eddi gian ch\u1ea5t l\u01b0\u1ee3ng cho m\u1ed9t m\u1ed1i quan h\u1ec7 quan tr\u1ecdng.", "Gi\u1ea3i quy\u1ebft m\u1ed9t vi\u1ec7c gia \u0111\u00ecnh ho\u1eb7c c\u00e1 nh\u00e2n \u0111ang ch\u1edd b\u1ea1n x\u1eed l\u00fd.", "T\u1ea1o m\u1ed9t kho\u1ea3ng ngh\u1ec9 ng\u1eafn \u0111\u1ec3 n\u1ea1p l\u1ea1i n\u0103ng l\u01b0\u1ee3ng trong ng\u00e0y.", "Tr\u00e1nh g\u00e1nh h\u1ebft tr\u00e1ch nhi\u1ec7m thay cho ng\u01b0\u1eddi kh\u00e1c."], "should_do": ["D\u00e0nh th\u1eddi gian ch\u1ea5t l\u01b0\u1ee3ng cho m\u1ed9t m\u1ed1i quan h\u1ec7 quan tr\u1ecdng.", "Gi\u1ea3i quy\u1ebft m\u1ed9t vi\u1ec7c gia \u0111\u00ecnh ho\u1eb7c c\u00e1 nh\u00e2n \u0111ang ch\u1edd b\u1ea1n x\u1eed l\u00fd."], "should_avoid": ["Tr\u00e1nh g\u00e1nh h\u1ebft tr\u00e1ch nhi\u1ec7m thay cho ng\u01b0\u1eddi kh\u00e1c."]}$json$::jsonb),
    (v_release_id, 'todaypersonalnumber', '7', $json${"quote": "Ch\u1eadm l\u1ea1i \u0111\u1ec3 l\u1eafng nghe tr\u1ef1c gi\u00e1c, c\u00e2u tr\u1ea3 l\u1eddi \u0111ang \u1edf b\u00ean trong b\u1ea1n.", "daily_rhythm": "T\u0129nh l\u1ea1i - Chi\u00eam nghi\u1ec7m", "detail": ["Ng\u00e0y c\u00e1 nh\u00e2n 7 thi\u00ean v\u1ec1 n\u1ed9i t\u00e2m, nghi\u00ean c\u1ee9u v\u00e0 chi\u1ec1u s\u00e2u nh\u1eadn th\u1ee9c.", "B\u1ea1n c\u00f3 th\u1ec3 c\u1ea7n kh\u00f4ng gian y\u00ean t\u0129nh \u0111\u1ec3 suy ngh\u0129 r\u00f5 tr\u01b0\u1edbc khi ra quy\u1ebft \u0111\u1ecbnh.", "N\u0103ng l\u01b0\u1ee3ng n\u00e0y ph\u00f9 h\u1ee3p cho vi\u1ec7c h\u1ecdc s\u00e2u, nh\u00ecn l\u1ea1i v\u00e0 \u0111i\u1ec1u ch\u1ec9nh h\u01b0\u1edbng \u0111i."], "hint_actions": ["D\u00e0nh \u00edt nh\u1ea5t 20-30 ph\u00fat \u1edf tr\u1ea1ng th\u00e1i t\u0129nh, kh\u00f4ng b\u1ecb xao nh\u00e3ng.", "Ghi l\u1ea1i m\u1ed9t c\u00e2u h\u1ecfi quan tr\u1ecdng v\u00e0 vi\u1ebft ra nh\u1eefng insight b\u1ea1n nh\u1eadn \u0111\u01b0\u1ee3c.", "\u01afu ti\u00ean c\u00f4ng vi\u1ec7c c\u1ea7n ph\u00e2n t\u00edch, t\u1ed5ng h\u1ee3p ho\u1eb7c nghi\u00ean c\u1ee9u.", "Tr\u00e1nh ph\u1ea3n \u1ee9ng ngay khi ch\u01b0a c\u00f3 \u0111\u1ee7 d\u1eef ki\u1ec7n."], "should_do": ["D\u00e0nh \u00edt nh\u1ea5t 20-30 ph\u00fat \u1edf tr\u1ea1ng th\u00e1i t\u0129nh, kh\u00f4ng b\u1ecb xao nh\u00e3ng.", "Ghi l\u1ea1i m\u1ed9t c\u00e2u h\u1ecfi quan tr\u1ecdng v\u00e0 vi\u1ebft ra nh\u1eefng insight b\u1ea1n nh\u1eadn \u0111\u01b0\u1ee3c."], "should_avoid": ["Tr\u00e1nh ph\u1ea3n \u1ee9ng ngay khi ch\u01b0a c\u00f3 \u0111\u1ee7 d\u1eef ki\u1ec7n."]}$json$::jsonb),
    (v_release_id, 'todaypersonalnumber', '8', $json${"quote": "H\u00f4m nay l\u00e0 nh\u1ecbp n\u0103ng l\u01b0\u1ee3ng c\u1ee7a hi\u1ec7u su\u1ea5t, m\u1ee5c ti\u00eau v\u00e0 k\u1ebft qu\u1ea3 r\u00f5 r\u00e0ng.", "daily_rhythm": "T\u1eadp trung - B\u1ee9t ph\u00e1", "detail": ["Ng\u00e0y c\u00e1 nh\u00e2n 8 nh\u1ea5n m\u1ea1nh th\u00e0nh t\u1ef1u, kh\u1ea3 n\u0103ng qu\u1ea3n tr\u1ecb v\u00e0 t\u01b0 duy chi\u1ebfn l\u01b0\u1ee3c.", "B\u1ea1n s\u1ebd ph\u00e1t huy t\u1ed1t khi l\u00e0m vi\u1ec7c v\u1edbi m\u1ee5c ti\u00eau \u0111o l\u01b0\u1eddng \u0111\u01b0\u1ee3c v\u00e0 deadline c\u1ee5 th\u1ec3.", "S\u1ef1 quy\u1ebft \u0111o\u00e1n \u0111i k\u00e8m k\u1ef7 lu\u1eadt gi\u00fap b\u1ea1n t\u1ea1o b\u01b0\u1edbc ti\u1ebfn \u0111\u00e1ng k\u1ec3 trong c\u00f4ng vi\u1ec7c."], "hint_actions": ["Ch\u1ed1t 1 m\u1ee5c ti\u00eau \u0111\u1ecbnh l\u01b0\u1ee3ng v\u00e0 theo d\u00f5i ti\u1ebfn \u0111\u1ed9 trong ng\u00e0y.", "\u01afu ti\u00ean nhi\u1ec7m v\u1ee5 t\u1ea1o t\u00e1c \u0111\u1ed9ng l\u1edbn \u0111\u1ebfn t\u00e0i ch\u00ednh ho\u1eb7c hi\u1ec7u qu\u1ea3 c\u00f4ng vi\u1ec7c.", "R\u00e0 so\u00e1t l\u1ea1i ngu\u1ed3n l\u1ef1c \u0111\u1ec3 t\u1ed1i \u01b0u c\u00e1ch tri\u1ec3n khai.", "Tr\u00e1nh sa \u0111\u00e0 v\u00e0o tranh lu\u1eadn c\u1ea3m t\u00ednh l\u00e0m m\u1ea5t n\u0103ng l\u01b0\u1ee3ng."], "should_do": ["Ch\u1ed1t 1 m\u1ee5c ti\u00eau \u0111\u1ecbnh l\u01b0\u1ee3ng v\u00e0 theo d\u00f5i ti\u1ebfn \u0111\u1ed9 trong ng\u00e0y.", "\u01afu ti\u00ean nhi\u1ec7m v\u1ee5 t\u1ea1o t\u00e1c \u0111\u1ed9ng l\u1edbn \u0111\u1ebfn t\u00e0i ch\u00ednh ho\u1eb7c hi\u1ec7u qu\u1ea3 c\u00f4ng vi\u1ec7c."], "should_avoid": ["Tr\u00e1nh sa \u0111\u00e0 v\u00e0o tranh lu\u1eadn c\u1ea3m t\u00ednh l\u00e0m m\u1ea5t n\u0103ng l\u01b0\u1ee3ng."]}$json$::jsonb),
    (v_release_id, 'todaypersonalnumber', '9', $json${"quote": "H\u00f4m nay ph\u00f9 h\u1ee3p \u0111\u1ec3 kh\u00e9p l\u1ea1i \u0111i\u1ec1u c\u0169 v\u00e0 m\u1edf l\u00f2ng cho chu k\u1ef3 m\u1edbi.", "daily_rhythm": "Ho\u00e0n t\u1ea5t - Bu\u00f4ng b\u1ecf", "detail": ["Ng\u00e0y c\u00e1 nh\u00e2n 9 l\u00e0 n\u0103ng l\u01b0\u1ee3ng c\u1ee7a ho\u00e0n th\u00e0nh, chuy\u1ec3n h\u00f3a v\u00e0 l\u00f2ng tr\u1eafc \u1ea9n.", "B\u1ea1n c\u00f3 th\u1ec3 nh\u1eadn ra \u0111i\u1ec1u g\u00ec kh\u00f4ng c\u00f2n ph\u00f9 h\u1ee3p \u0111\u1ec3 d\u1eebng l\u1ea1i m\u1ed9t c\u00e1ch nh\u1eb9 nh\u00e0ng.", "Khi d\u1ecdn d\u1eb9p \u0111\u01b0\u1ee3c ph\u1ea7n c\u0169, b\u1ea1n s\u1ebd c\u00f3 kh\u00f4ng gian t\u1ed1t h\u01a1n cho giai \u0111o\u1ea1n m\u1edbi."], "hint_actions": ["Ho\u00e0n t\u1ea5t m\u1ed9t vi\u1ec7c dang d\u1edf \u0111\u00e3 k\u00e9o d\u00e0i nhi\u1ec1u ng\u00e0y.", "Bu\u00f4ng b\u1ecf m\u1ed9t th\u00f3i quen ho\u1eb7c k\u1ef3 v\u1ecdng kh\u00f4ng c\u00f2n ph\u00f9 h\u1ee3p.", "Th\u1ef1c hi\u1ec7n m\u1ed9t h\u00e0nh \u0111\u1ed9ng t\u1eed t\u1ebf cho ng\u01b0\u1eddi xung quanh.", "Tr\u00e1nh n\u00edu gi\u1eef c\u00e1c cam k\u1ebft \u0111\u00e3 h\u1ebft gi\u00e1 tr\u1ecb th\u1ef1c t\u1ebf."], "should_do": ["Ho\u00e0n t\u1ea5t m\u1ed9t vi\u1ec7c dang d\u1edf \u0111\u00e3 k\u00e9o d\u00e0i nhi\u1ec1u ng\u00e0y.", "Bu\u00f4ng b\u1ecf m\u1ed9t th\u00f3i quen ho\u1eb7c k\u1ef3 v\u1ecdng kh\u00f4ng c\u00f2n ph\u00f9 h\u1ee3p."], "should_avoid": ["Tr\u00e1nh n\u00edu gi\u1eef c\u00e1c cam k\u1ebft \u0111\u00e3 h\u1ebft gi\u00e1 tr\u1ecb th\u1ef1c t\u1ebf."]}$json$::jsonb),
    (v_release_id, 'month_personal_number', '1', $json${"keyword": "Kh\u1edfi \u0111\u1ea7u", "hero_title": "Th\u00e1ng c\u00e1 nh\u00e2n 1", "focus": ["\u0110\u00e2y l\u00e0 th\u00e1ng ph\u00f9 h\u1ee3p \u0111\u1ec3 b\u1eaft \u0111\u1ea7u h\u01b0\u1edbng \u0111i m\u1edbi v\u00e0 t\u1ef1 ch\u1ee7 trong quy\u1ebft \u0111\u1ecbnh.", "N\u0103ng l\u01b0\u1ee3ng s\u1ed1 1 th\u00fac \u0111\u1ea9y b\u1ea1n h\u00e0nh \u0111\u1ed9ng nhanh, r\u00f5 m\u1ee5c ti\u00eau v\u00e0 d\u00e1m d\u1eabn d\u1eaft."], "steps": [{"title": "X\u00e1c \u0111\u1ecbnh \u01b0u ti\u00ean ch\u00ednh", "body": "Ch\u1ecdn 1 m\u1ee5c ti\u00eau quan tr\u1ecdng nh\u1ea5t cho th\u00e1ng n\u00e0y v\u00e0 b\u00e1m theo n\u00f3."}, {"title": "Ch\u1ee7 \u0111\u1ed9ng kh\u1edfi \u0111\u1ed9ng", "body": "Th\u1ef1c hi\u1ec7n b\u01b0\u1edbc \u0111\u1ea7u ti\u00ean s\u1edbm thay v\u00ec ch\u1edd \u0111i\u1ec1u ki\u1ec7n ho\u00e0n h\u1ea3o."}, {"title": "Gi\u1eef nh\u1ecbp quy\u1ebft \u0111o\u00e1n", "body": "\u0110\u01b0a ra quy\u1ebft \u0111\u1ecbnh d\u1ef1a tr\u00ean d\u1eef ki\u1ec7n v\u00e0 tr\u00e1ch nhi\u1ec7m c\u00e1 nh\u00e2n."}], "priorities": ["Kh\u1edfi \u0111\u1ed9ng d\u1ef1 \u00e1n ho\u1eb7c k\u1ebf ho\u1ea1ch m\u1edbi", "Thi\u1ebft l\u1eadp m\u1ee5c ti\u00eau \u0111o l\u01b0\u1eddng r\u00f5 r\u00e0ng", "R\u00e8n th\u00f3i quen ch\u1ee7 \u0111\u1ed9ng m\u1ed7i ng\u00e0y", "Gi\u1eef t\u01b0 duy ti\u00ean phong trong c\u00f4ng vi\u1ec7c"], "cautions": ["Tr\u00e1nh n\u00f3ng v\u1ed9i khi ch\u01b0a \u0111\u1ee7 th\u00f4ng tin", "Tr\u00e1nh l\u00e0m vi\u1ec7c m\u1ed9t m\u00ecnh trong m\u1ecdi t\u00ecnh hu\u1ed1ng", "Tr\u00e1nh \u0111\u1eb7t qu\u00e1 nhi\u1ec1u m\u1ee5c ti\u00eau c\u00f9ng l\u00fac"]}$json$::jsonb),
