    (v_release_id, 'month_personal_number', '8', $json${"keyword": "Th\u00e0nh t\u1ef1u", "hero_title": "Th\u00e1ng c\u00e1 nh\u00e2n 8", "focus": ["Th\u00e1ng n\u00e0y \u01b0u ti\u00ean hi\u1ec7u su\u1ea5t, k\u1ebft qu\u1ea3 v\u00e0 kh\u1ea3 n\u0103ng qu\u1ea3n tr\u1ecb ngu\u1ed3n l\u1ef1c.", "B\u1ea1n s\u1ebd t\u0103ng tr\u01b0\u1edfng m\u1ea1nh khi l\u00e0m vi\u1ec7c v\u1edbi m\u1ee5c ti\u00eau \u0111\u1ecbnh l\u01b0\u1ee3ng v\u00e0 chi\u1ebfn l\u01b0\u1ee3c r\u00f5 r\u00e0ng."], "steps": [{"title": "\u0110\u1eb7t m\u1ee5c ti\u00eau \u0111o l\u01b0\u1eddng", "body": "X\u00e1c \u0111\u1ecbnh ch\u1ec9 s\u1ed1 k\u1ebft qu\u1ea3 cho t\u1eebng m\u1ea3ng quan tr\u1ecdng trong th\u00e1ng."}, {"title": "Ph\u00e2n b\u1ed5 ngu\u1ed3n l\u1ef1c h\u1ee3p l\u00fd", "body": "D\u1ed3n th\u1eddi gian v\u00e0 n\u0103ng l\u01b0\u1ee3ng v\u00e0o nhi\u1ec7m v\u1ee5 t\u1ea1o t\u00e1c \u0111\u1ed9ng l\u1edbn."}, {"title": "R\u00e0 so\u00e1t hi\u1ec7u qu\u1ea3 \u0111\u1ecbnh k\u1ef3", "body": "Theo d\u00f5i ti\u1ebfn \u0111\u1ed9 h\u00e0ng tu\u1ea7n v\u00e0 \u0111i\u1ec1u ch\u1ec9nh k\u1ebf ho\u1ea1ch theo d\u1eef li\u1ec7u."}], "priorities": ["T\u1eadp trung k\u1ebft qu\u1ea3 c\u00f4ng vi\u1ec7c tr\u1ecdng y\u1ebfu", "N\u00e2ng n\u0103ng l\u1ef1c qu\u1ea3n tr\u1ecb v\u00e0 l\u00e3nh \u0111\u1ea1o", "T\u1ed1i \u01b0u d\u00f2ng ti\u1ec1n ho\u1eb7c t\u00e0i ch\u00ednh c\u00e1 nh\u00e2n", "X\u00e2y n\u1ec1n cho m\u1ee5c ti\u00eau d\u00e0i h\u1ea1n"], "cautions": ["Tr\u00e1nh l\u00e0m vi\u1ec7c ch\u1ec9 v\u00ec th\u00e0nh t\u00edch ng\u1eafn h\u1ea1n", "Tr\u00e1nh c\u0103ng th\u1eb3ng k\u00e9o d\u00e0i v\u00ec ki\u1ec3m so\u00e1t qu\u00e1 m\u1ee9c", "Tr\u00e1nh quy\u1ebft \u0111\u1ecbnh t\u00e0i ch\u00ednh theo c\u1ea3m x\u00fac"]}$json$::jsonb),
    (v_release_id, 'month_personal_number', '9', $json${"keyword": "Ho\u00e0n t\u1ea5t", "hero_title": "Th\u00e1ng c\u00e1 nh\u00e2n 9", "focus": ["Th\u00e1ng n\u00e0y mang n\u0103ng l\u01b0\u1ee3ng kh\u00e9p chu k\u1ef3, gi\u1ea3i ph\u00f3ng \u0111i\u1ec1u c\u0169 v\u00e0 m\u1edf kh\u00f4ng gian m\u1edbi.", "B\u1ea1n ph\u00f9 h\u1ee3p \u0111\u1ec3 t\u1ed5ng k\u1ebft, ho\u00e0n thi\u1ec7n v\u00e0 ch\u1ecdn l\u1ecdc l\u1ea1i nh\u1eefng cam k\u1ebft \u0111ang c\u00f3."], "steps": [{"title": "R\u00e0 so\u00e1t to\u00e0n b\u1ed9 danh m\u1ee5c vi\u1ec7c", "body": "X\u00e1c \u0111\u1ecbnh \u0111i\u1ec1u c\u1ea7n ho\u00e0n t\u1ea5t ngay v\u00e0 \u0111i\u1ec1u n\u00ean bu\u00f4ng b\u1ecf."}, {"title": "Kh\u00e9p c\u00e1c v\u00f2ng l\u1eb7p ch\u01b0a xong", "body": "Gi\u1ea3i quy\u1ebft d\u1ee9t \u0111i\u1ec3m nh\u1eefng \u0111\u1ea7u vi\u1ec7c k\u00e9o d\u00e0i g\u00e2y ti\u00eau hao n\u0103ng l\u01b0\u1ee3ng."}, {"title": "Chu\u1ea9n b\u1ecb cho chu k\u1ef3 m\u1edbi", "body": "Gi\u1eef l\u1ea1i \u0111i\u1ec1u c\u00f3 gi\u00e1 tr\u1ecb, lo\u1ea1i b\u1ecf ph\u1ea7n kh\u00f4ng c\u00f2n ph\u00f9 h\u1ee3p."}], "priorities": ["Ho\u00e0n th\u00e0nh c\u00e1c cam k\u1ebft quan tr\u1ecdng", "D\u1ecdn d\u1eb9p h\u1ec7 th\u1ed1ng v\u00e0 kh\u00f4ng gian s\u1ed1ng", "Th\u1ef1c h\u00e0nh tha th\u1ee9 v\u00e0 bu\u00f4ng b\u1ecf", "T\u1ed5ng k\u1ebft b\u00e0i h\u1ecdc cho giai \u0111o\u1ea1n ti\u1ebfp theo"], "cautions": ["Tr\u00e1nh n\u00edu k\u00e9o \u0111i\u1ec1u \u0111\u00e3 h\u1ebft v\u00f2ng \u0111\u1eddi", "Tr\u00e1nh ra quy\u1ebft \u0111\u1ecbnh n\u00f3ng trong c\u1ea3m x\u00fac m\u1ea1nh", "Tr\u00e1nh tr\u00ec ho\u00e3n vi\u1ec7c k\u1ebft th\u00fac c\u1ea7n thi\u1ebft"]}$json$::jsonb),
    (v_release_id, 'year_personal_number', '1', $json${"keyword": "Kh\u1edfi \u0111\u1ea7u", "hero_title": "N\u0103m c\u00e1 nh\u00e2n 1", "theme": ["\u0110\u00e2y l\u00e0 n\u0103m m\u1edf chu k\u1ef3 m\u1edbi, ph\u00f9 h\u1ee3p \u0111\u1ec3 x\u00e1c l\u1eadp h\u01b0\u1edbng \u0111i v\u00e0 b\u1ea3n s\u1eafc c\u00e1 nh\u00e2n.", "B\u1ea1n s\u1ebd m\u1ea1nh h\u01a1n khi ch\u1ee7 \u0111\u1ed9ng b\u1eaft \u0111\u1ea7u, t\u1ef1 quy\u1ebft v\u00e0 d\u00e1m ch\u1ecbu tr\u00e1ch nhi\u1ec7m.", "N\u1ec1n t\u1ea3ng b\u1ea1n x\u00e2y trong n\u0103m 1 s\u1ebd \u1ea3nh h\u01b0\u1edfng tr\u1ef1c ti\u1ebfp \u0111\u1ebfn to\u00e0n b\u1ed9 chu k\u1ef3 ti\u1ebfp theo."], "lessons": [{"title": "Ch\u1ee7 \u0111\u1ed9ng", "body": "\u0110\u1eebng ch\u1edd \u0111\u1ee3i th\u1eddi \u0111i\u1ec3m ho\u00e0n h\u1ea3o, h\u00e3y t\u1ea1o \u0111\u00e0 b\u1eb1ng h\u00e0nh \u0111\u1ed9ng r\u00f5 r\u00e0ng."}, {"title": "Quy\u1ebft \u0111o\u00e1n", "body": "R\u00e8n k\u1ef9 n\u0103ng ch\u1ecdn nhanh d\u1ef1a tr\u00ean d\u1eef li\u1ec7u thay v\u00ec do d\u1ef1 k\u00e9o d\u00e0i."}, {"title": "T\u1ef1 ch\u1ee7", "body": "X\u00e2y th\u00f3i quen t\u1ef1 ch\u1ecbu tr\u00e1ch nhi\u1ec7m v\u1edbi m\u1ee5c ti\u00eau \u0111\u00e3 \u0111\u1eb7t ra."}], "focus_areas": [{"title": "S\u1ef1 nghi\u1ec7p", "body": "Kh\u1edfi \u0111\u1ed9ng vai tr\u00f2 m\u1edbi ho\u1eb7c h\u01b0\u1edbng ph\u00e1t tri\u1ec3n m\u1edbi."}, {"title": "T\u00e0i ch\u00ednh", "body": "Thi\u1ebft l\u1eadp h\u1ec7 quy t\u1eafc qu\u1ea3n l\u00fd ti\u1ec1n cho chu k\u1ef3 d\u00e0i h\u1ea1n."}, {"title": "M\u1ee5c ti\u00eau", "body": "X\u00e1c \u0111\u1ecbnh 1-2 m\u1ee5c ti\u00eau tr\u1ecdng t\u00e2m cho c\u1ea3 n\u0103m."}, {"title": "C\u00e2n b\u1eb1ng", "body": "Gi\u1eef nh\u1ecbp l\u00e0m vi\u1ec7c b\u1ec1n \u0111\u1ec3 tr\u00e1nh \u0111\u1ed1t n\u0103ng l\u01b0\u1ee3ng qu\u00e1 s\u1edbm."}]}$json$::jsonb),
    (v_release_id, 'year_personal_number', '2', $json${"keyword": "H\u1ee3p t\u00e1c", "hero_title": "N\u0103m c\u00e1 nh\u00e2n 2", "theme": ["N\u0103m 2 nh\u1ea5n m\u1ea1nh s\u1ef1 \u0111\u1ed3ng h\u00e0nh, tinh t\u1ebf c\u1ea3m x\u00fac v\u00e0 x\u00e2y d\u1ef1ng quan h\u1ec7 b\u1ec1n v\u1eefng.", "T\u0103ng tr\u01b0\u1edfng trong n\u0103m n\u00e0y \u0111\u1ebfn t\u1eeb ch\u1ea5t l\u01b0\u1ee3ng h\u1ee3p t\u00e1c h\u01a1n l\u00e0 t\u1ed1c \u0111\u1ed9 c\u00e1 nh\u00e2n.", "Ki\u00ean nh\u1eabn v\u00e0 ngo\u1ea1i giao s\u1ebd m\u1edf ra c\u01a1 h\u1ed9i \u1ed5n \u0111\u1ecbnh l\u00e2u d\u00e0i."], "lessons": [{"title": "Ki\u00ean nh\u1eabn", "body": "Cho ph\u00e9p ti\u1ebfn tr\u00ecnh ph\u00e1t tri\u1ec3n t\u1ef1 nhi\u00ean thay v\u00ec \u00e9p nhanh k\u1ebft qu\u1ea3."}, {"title": "L\u1eafng nghe", "body": "N\u00e2ng ch\u1ea5t l\u01b0\u1ee3ng giao ti\u1ebfp b\u1eb1ng c\u00e1ch hi\u1ec3u s\u00e2u \u0111\u1ed9ng l\u1ef1c c\u1ee7a ng\u01b0\u1eddi kh\u00e1c."}, {"title": "\u0110i\u1ec1u h\u00f2a", "body": "Bi\u1ebft c\u00e2n b\u1eb1ng l\u1ee3i \u00edch v\u00e0 c\u1ea3m x\u00fac trong c\u00e1c m\u1ed1i quan h\u1ec7 ch\u00ednh."}], "focus_areas": [{"title": "S\u1ef1 nghi\u1ec7p", "body": "Ph\u00e1t tri\u1ec3n th\u00f4ng qua l\u00e0m vi\u1ec7c nh\u00f3m v\u00e0 \u0111\u1ed1i t\u00e1c chi\u1ebfn l\u01b0\u1ee3c."}, {"title": "T\u00e0i ch\u00ednh", "body": "\u01afu ti\u00ean \u1ed5n \u0111\u1ecbnh v\u00e0 qu\u1ea3n tr\u1ecb r\u1ee7i ro thay v\u00ec m\u1ea1o hi\u1ec3m cao."}, {"title": "M\u1ee5c ti\u00eau", "body": "Chia k\u1ebf ho\u1ea1ch th\u00e0nh giai \u0111o\u1ea1n nh\u1ecf \u0111\u1ec3 duy tr\u00ec b\u1ec1n b\u1ec9."}, {"title": "C\u00e2n b\u1eb1ng", "body": "Gi\u1eef ranh gi\u1edbi c\u1ea3m x\u00fac \u0111\u1ec3 kh\u00f4ng b\u1ecb cu\u1ed1n v\u00e0o \u00e1p l\u1ef1c quan h\u1ec7."}]}$json$::jsonb),
    (v_release_id, 'year_personal_number', '3', $json${"keyword": "Bi\u1ec3u \u0111\u1ea1t", "hero_title": "N\u0103m c\u00e1 nh\u00e2n 3", "theme": ["N\u0103m 3 m\u1edf r\u1ed9ng s\u00e1ng t\u1ea1o, giao ti\u1ebfp v\u00e0 s\u1ee9c \u1ea3nh h\u01b0\u1edfng c\u00e1 nh\u00e2n.", "B\u1ea1n thu\u1eadn l\u1ee3i khi chia s\u1ebb \u00fd t\u01b0\u1edfng, x\u00e2y th\u01b0\u01a1ng hi\u1ec7u c\u00e1 nh\u00e2n v\u00e0 k\u1ebft n\u1ed1i c\u1ed9ng \u0111\u1ed3ng.", "K\u1ef7 lu\u1eadt trong th\u1ef1c thi s\u1ebd gi\u00fap c\u1ea3m h\u1ee9ng chuy\u1ec3n th\u00e0nh th\u00e0nh t\u1ef1u th\u1ef1c t\u1ebf."], "lessons": [{"title": "Bi\u1ec3u \u0111\u1ea1t r\u00f5 r\u00e0ng", "body": "R\u00e8n kh\u1ea3 n\u0103ng truy\u1ec1n \u0111\u1ea1t th\u00f4ng \u0111i\u1ec7p ng\u1eafn g\u1ecdn v\u00e0 thuy\u1ebft ph\u1ee5c."}, {"title": "S\u00e1ng t\u1ea1o c\u00f3 c\u1ea5u tr\u00fac", "body": "Duy tr\u00ec l\u1ecbch l\u00e0m vi\u1ec7c \u0111\u1ec3 \u00fd t\u01b0\u1edfng kh\u00f4ng b\u1ecb r\u01a1i r\u1ee5ng."}, {"title": "Hi\u1ec7n di\u1ec7n t\u00edch c\u1ef1c", "body": "Lan t\u1ecfa n\u0103ng l\u01b0\u1ee3ng t\u1ed1t nh\u01b0ng v\u1eabn gi\u1eef m\u1ee5c ti\u00eau tr\u1ecdng t\u00e2m."}], "focus_areas": [{"title": "S\u1ef1 nghi\u1ec7p", "body": "T\u0103ng hi\u1ec7n di\u1ec7n th\u00f4ng qua thuy\u1ebft tr\u00ecnh, n\u1ed9i dung ho\u1eb7c truy\u1ec1n th\u00f4ng."}, {"title": "T\u00e0i ch\u00ednh", "body": "M\u1edf th\u00eam ngu\u1ed3n thu t\u1eeb k\u1ef9 n\u0103ng s\u00e1ng t\u1ea1o/giao ti\u1ebfp."}, {"title": "M\u1ee5c ti\u00eau", "body": "X\u00e2y k\u1ebf ho\u1ea1ch theo qu\u00fd cho c\u00e1c d\u1ef1 \u00e1n c\u00f3 t\u00ednh c\u00f4ng khai."}, {"title": "C\u00e2n b\u1eb1ng", "body": "Tr\u00e1nh ph\u00e2n t\u00e1n b\u1eb1ng c\u00e1ch gi\u1edbi h\u1ea1n s\u1ed1 d\u1ef1 \u00e1n \u0111ang ch\u1ea1y."}]}$json$::jsonb),
    (v_release_id, 'year_personal_number', '4', $json${"keyword": "N\u1ec1n t\u1ea3ng", "hero_title": "N\u0103m c\u00e1 nh\u00e2n 4", "theme": ["N\u0103m 4 l\u00e0 giai \u0111o\u1ea1n c\u1ee7ng c\u1ed1 h\u1ec7 th\u1ed1ng, k\u1ef7 lu\u1eadt v\u00e0 n\u0103ng l\u1ef1c v\u1eadn h\u00e0nh.", "Th\u00e0nh qu\u1ea3 \u0111\u1ebfn t\u1eeb l\u00e0m \u0111\u00fang quy tr\u00ecnh, \u0111\u1ec1u \u0111\u1eb7n v\u00e0 th\u1ef1c t\u1ebf.", "\u0110\u00e2y l\u00e0 n\u0103m th\u00edch h\u1ee3p \u0111\u1ec3 x\u00e2y c\u01a1 s\u1edf ch\u1eafc cho m\u1ee5c ti\u00eau d\u00e0i h\u1ea1n."], "lessons": [{"title": "K\u1ef7 lu\u1eadt", "body": "Thi\u1ebft l\u1eadp nh\u1ecbp l\u00e0m vi\u1ec7c c\u1ed1 \u0111\u1ecbnh v\u00e0 tu\u00e2n th\u1ee7 nh\u1ea5t qu\u00e1n."}, {"title": "T\u1ed5 ch\u1ee9c", "body": "Chu\u1ea9n h\u00f3a quy tr\u00ecnh \u0111\u1ec3 gi\u1ea3m l\u1ed7i v\u00e0 ti\u1ebft ki\u1ec7m ngu\u1ed3n l\u1ef1c."}, {"title": "Ki\u00ean tr\u00ec", "body": "T\u1eadp trung v\u00e0o ti\u1ebfn b\u1ed9 nh\u1ecf m\u1ed7i ng\u00e0y thay v\u00ec b\u00f9ng n\u1ed5 ng\u1eafn h\u1ea1n."}], "focus_areas": [{"title": "S\u1ef1 nghi\u1ec7p", "body": "T\u1ed1i \u01b0u h\u1ec7 v\u1eadn h\u00e0nh, vai tr\u00f2 v\u00e0 ti\u00eau chu\u1ea9n ch\u1ea5t l\u01b0\u1ee3ng."}, {"title": "T\u00e0i ch\u00ednh", "body": "\u01afu ti\u00ean ng\u00e2n s\u00e1ch an to\u00e0n v\u00e0 k\u1ebf ho\u1ea1ch t\u00edch l\u0169y \u1ed5n \u0111\u1ecbnh."}, {"title": "M\u1ee5c ti\u00eau", "body": "Chuy\u1ec3n m\u1ee5c ti\u00eau l\u1edbn th\u00e0nh k\u1ebf ho\u1ea1ch th\u1ef1c thi theo m\u1ed1c."}, {"title": "C\u00e2n b\u1eb1ng", "body": "Gi\u1eef k\u1ef7 lu\u1eadt ngh\u1ec9 ng\u01a1i \u0111\u1ec3 duy tr\u00ec hi\u1ec7u su\u1ea5t b\u1ec1n v\u1eefng."}]}$json$::jsonb),
    (v_release_id, 'year_personal_number', '5', $json${"keyword": "Thay \u0111\u1ed5i", "hero_title": "N\u0103m c\u00e1 nh\u00e2n 5", "theme": ["N\u0103m 5 l\u00e0 n\u0103m chuy\u1ec3n \u0111\u1ed9ng m\u1ea1nh, m\u1edf r\u1ed9ng tr\u1ea3i nghi\u1ec7m v\u00e0 t\u00e1i c\u1ea5u tr\u00fac linh ho\u1ea1t.", "C\u01a1 h\u1ed9i th\u01b0\u1eddng \u0111\u1ebfn nhanh, \u0111\u00f2i h\u1ecfi b\u1ea1n th\u00edch nghi v\u00e0 ch\u1ecdn l\u1ecdc th\u00f4ng minh.", "Gi\u1eef m\u1ee5c ti\u00eau l\u00f5i r\u00f5 r\u00e0ng s\u1ebd gi\u00fap b\u1ea1n kh\u00f4ng b\u1ecb cu\u1ed1n v\u00e0o ph\u00e2n t\u00e1n."], "lessons": [{"title": "Linh ho\u1ea1t", "body": "S\u1eb5n s\u00e0ng \u0111\u1ed5i c\u00e1ch l\u00e0m khi b\u1ed1i c\u1ea3nh thay \u0111\u1ed5i."}, {"title": "Ch\u1ecdn l\u1ecdc", "body": "Kh\u00f4ng ph\u1ea3i c\u01a1 h\u1ed9i n\u00e0o c\u0169ng c\u1ea7n n\u1eafm, \u01b0u ti\u00ean c\u00e1i ph\u00f9 h\u1ee3p chi\u1ebfn l\u01b0\u1ee3c."}, {"title": "T\u1ef1 do c\u00f3 k\u1ef7 lu\u1eadt", "body": "M\u1edf r\u1ed9ng tr\u1ea3i nghi\u1ec7m nh\u01b0ng v\u1eabn gi\u1eef nguy\u00ean t\u1eafc v\u1eadn h\u00e0nh c\u1ed1t l\u00f5i."}], "focus_areas": [{"title": "S\u1ef1 nghi\u1ec7p", "body": "Th\u1eed m\u00f4 h\u00ecnh l\u00e0m vi\u1ec7c m\u1edbi v\u00e0 m\u1edf r\u1ed9ng quan h\u1ec7 chuy\u00ean m\u00f4n."}, {"title": "T\u00e0i ch\u00ednh", "body": "\u0110a d\u1ea1ng h\u00f3a ngu\u1ed3n thu nh\u01b0ng ki\u1ec3m so\u00e1t r\u1ee7i ro."}, {"title": "M\u1ee5c ti\u00eau", "body": "Thi\u1ebft k\u1ebf m\u1ee5c ti\u00eau linh ho\u1ea1t theo t\u1eebng qu\u00fd."}, {"title": "C\u00e2n b\u1eb1ng", "body": "Gi\u1eef \u0111i\u1ec3m neo c\u00e1 nh\u00e2n \u0111\u1ec3 kh\u00f4ng b\u1ecb qu\u00e1 t\u1ea3i b\u1edfi thay \u0111\u1ed5i."}]}$json$::jsonb),
    (v_release_id, 'year_personal_number', '6', $json${"keyword": "Tr\u00e1ch nhi\u1ec7m", "hero_title": "N\u0103m c\u00e1 nh\u00e2n 6", "theme": ["N\u0103m 6 t\u1eadp trung v\u00e0o gia \u0111\u00ecnh, c\u1ed9ng \u0111\u1ed3ng, s\u1ef1 ch\u0103m s\u00f3c v\u00e0 tr\u00e1ch nhi\u1ec7m.", "B\u1ea1n \u0111\u01b0\u1ee3c m\u1eddi g\u1ecdi c\u00e2n b\u1eb1ng gi\u1eefa c\u1ed1ng hi\u1ebfn cho ng\u01b0\u1eddi kh\u00e1c v\u00e0 ch\u0103m s\u00f3c ch\u00ednh m\u00ecnh.", "C\u00e1c quy\u1ebft \u0111\u1ecbnh trong n\u0103m n\u00e0y n\u00ean \u0111\u1eb7t tr\u00ean n\u1ec1n t\u1ea3ng gi\u00e1 tr\u1ecb v\u00e0 s\u1ef1 h\u00e0i h\u00f2a l\u00e2u d\u00e0i."], "lessons": [{"title": "Bao dung c\u00f3 ranh gi\u1edbi", "body": "Bi\u1ebft h\u1ed7 tr\u1ee3 ng\u01b0\u1eddi kh\u00e1c m\u00e0 kh\u00f4ng \u0111\u00e1nh m\u1ea5t n\u0103ng l\u01b0\u1ee3ng b\u1ea3n th\u00e2n."}, {"title": "Cam k\u1ebft", "body": "Gi\u1eef l\u1eddi h\u1ee9a v\u1edbi nh\u1eefng tr\u00e1ch nhi\u1ec7m quan tr\u1ecdng trong quan h\u1ec7."}, {"title": "H\u00e0i h\u00f2a", "body": "X\u1eed l\u00fd xung \u0111\u1ed9t b\u1eb1ng th\u1ea5u hi\u1ec3u v\u00e0 giao ti\u1ebfp r\u00f5 r\u00e0ng."}], "focus_areas": [{"title": "S\u1ef1 nghi\u1ec7p", "body": "Ph\u00e1t tri\u1ec3n vai tr\u00f2 t\u1ea1o gi\u00e1 tr\u1ecb cho t\u1eadp th\u1ec3 v\u00e0 con ng\u01b0\u1eddi."}, {"title": "T\u00e0i ch\u00ednh", "body": "\u01afu ti\u00ean chi ti\u00eau cho nhu c\u1ea7u c\u1ed1t l\u00f5i v\u00e0 an to\u00e0n gia \u0111\u00ecnh."}, {"title": "M\u1ee5c ti\u00eau", "body": "C\u00e2n b\u1eb1ng m\u1ee5c ti\u00eau c\u00e1 nh\u00e2n v\u1edbi tr\u00e1ch nhi\u1ec7m chung."}, {"title": "C\u00e2n b\u1eb1ng", "body": "Duy tr\u00ec ch\u0103m s\u00f3c s\u1ee9c kh\u1ecfe c\u1ea3m x\u00fac v\u00e0 th\u1ec3 ch\u1ea5t \u0111\u1ecbnh k\u1ef3."}]}$json$::jsonb),
    (v_release_id, 'year_personal_number', '7', $json${"keyword": "Chi\u00eam nghi\u1ec7m", "hero_title": "N\u0103m c\u00e1 nh\u00e2n 7", "theme": ["N\u0103m 7 l\u00e0 n\u0103m c\u1ee7a chi\u1ec1u s\u00e2u, h\u1ecdc t\u1eadp, nghi\u00ean c\u1ee9u v\u00e0 ph\u00e1t tri\u1ec3n n\u1ed9i t\u00e2m.", "\u0110\u00e2y l\u00e0 giai \u0111o\u1ea1n n\u00ean gi\u1ea3m t\u1ed1c \u0111\u1ec3 quan s\u00e1t v\u00e0 \u0111\u1ecbnh v\u1ecb l\u1ea1i h\u01b0\u1edbng \u0111i d\u00e0i h\u1ea1n.", "Ch\u1ea5t l\u01b0\u1ee3ng t\u01b0 duy v\u00e0 tr\u1ef1c gi\u00e1c s\u1ebd quy\u1ebft \u0111\u1ecbnh \u0111\u1ed9 ch\u00ednh x\u00e1c c\u1ee7a c\u00e1c quy\u1ebft \u0111\u1ecbnh l\u1edbn."], "lessons": [{"title": "\u0110\u00e0o s\u00e2u", "body": "T\u1eadp trung v\u00e0o hi\u1ec3u b\u1ea3n ch\u1ea5t thay v\u00ec x\u1eed l\u00fd b\u1ec1 m\u1eb7t v\u1ea5n \u0111\u1ec1."}, {"title": "Ki\u1ec3m ch\u1ee9ng", "body": "K\u1ebft h\u1ee3p tr\u1ef1c gi\u00e1c v\u1edbi d\u1eef ki\u1ec7n tr\u01b0\u1edbc khi ch\u1ed1t h\u01b0\u1edbng quan tr\u1ecdng."}, {"title": "T\u0129nh t\u00e2m", "body": "Duy tr\u00ec kh\u00f4ng gian y\u00ean t\u0129nh \u0111\u1ec3 t\u00e1i t\u1ea1o n\u0103ng l\u01b0\u1ee3ng tr\u00ed tu\u1ec7."}], "focus_areas": [{"title": "S\u1ef1 nghi\u1ec7p", "body": "N\u00e2ng chuy\u00ean m\u00f4n chi\u1ec1u s\u00e2u v\u00e0 x\u00e2y n\u1ec1n tri th\u1ee9c v\u1eefng ch\u1eafc."}, {"title": "T\u00e0i ch\u00ednh", "body": "\u01afu ti\u00ean an to\u00e0n v\u00e0 quy\u1ebft \u0111\u1ecbnh d\u1ef1a tr\u00ean ph\u00e2n t\u00edch th\u1eadn tr\u1ecdng."}, {"title": "M\u1ee5c ti\u00eau", "body": "R\u00e0 so\u00e1t l\u1ea1i m\u1ee5c ti\u00eau d\u00e0i h\u1ea1n \u0111\u1ec3 lo\u1ea1i b\u1ecf ph\u1ea7n kh\u00f4ng c\u00f2n ph\u00f9 h\u1ee3p."}, {"title": "C\u00e2n b\u1eb1ng", "body": "Gi\u1ea3m nhi\u1ec5u th\u00f4ng tin, t\u0103ng th\u1eddi gian h\u1ed3i ph\u1ee5c tinh th\u1ea7n."}]}$json$::jsonb),
    (v_release_id, 'year_personal_number', '8', $json${"keyword": "Th\u00e0nh t\u1ef1u", "hero_title": "N\u0103m c\u00e1 nh\u00e2n 8", "theme": ["\u0110\u00e2y l\u00e0 n\u0103m t\u1eadp trung v\u00e0o k\u1ebft qu\u1ea3, n\u0103ng l\u1ef1c qu\u1ea3n tr\u1ecb v\u00e0 m\u1ee5c ti\u00eau d\u00e0i h\u1ea1n.", "B\u1ea1n c\u00f3 c\u01a1 h\u1ed9i t\u1ea1o b\u01b0\u1edbc ti\u1ebfn r\u00f5 r\u1ec7t n\u1ebfu duy tr\u00ec k\u1ef7 lu\u1eadt v\u00e0 t\u01b0 duy chi\u1ebfn l\u01b0\u1ee3c.", "Gi\u1eef c\u00e2n b\u1eb1ng gi\u1eefa tham v\u1ecdng, tr\u00e1ch nhi\u1ec7m v\u00e0 s\u1ee9c kh\u1ecfe s\u1ebd gi\u00fap b\u1ea1n b\u1ec1n v\u1eefng."], "lessons": [{"title": "K\u1ef7 lu\u1eadt", "body": "Thi\u1ebft k\u1ebf nh\u1ecbp l\u00e0m vi\u1ec7c \u1ed5n \u0111\u1ecbnh \u0111\u1ec3 duy tr\u00ec ti\u1ebfn \u0111\u1ed9 c\u1ea3 n\u0103m."}, {"title": "Tr\u00e1ch nhi\u1ec7m", "body": "Ra quy\u1ebft \u0111\u1ecbnh r\u00f5 r\u00e0ng v\u00e0 ch\u1ecbu tr\u00e1ch nhi\u1ec7m v\u1edbi k\u1ebft qu\u1ea3 c\u1ee7a m\u00ecnh."}, {"title": "C\u00e2n b\u1eb1ng tham v\u1ecdng", "body": "Theo \u0111u\u1ed5i m\u1ee5c ti\u00eau l\u1edbn nh\u01b0ng kh\u00f4ng \u0111\u00e1nh \u0111\u1ed5i c\u00e1c gi\u00e1 tr\u1ecb c\u1ed1t l\u00f5i."}], "focus_areas": [{"title": "S\u1ef1 nghi\u1ec7p", "body": "T\u0103ng v\u1ecb th\u1ebf chuy\u00ean m\u00f4n, n\u00e2ng ch\u1ea5t l\u01b0\u1ee3ng \u0111\u1ea7u ra v\u00e0 vai tr\u00f2 d\u1eabn d\u1eaft."}, {"title": "T\u00e0i ch\u00ednh", "body": "Qu\u1ea3n tr\u1ecb ng\u00e2n s\u00e1ch v\u00e0 \u0111\u1ea7u t\u01b0 theo k\u1ebf ho\u1ea1ch c\u00f3 ki\u1ec3m so\u00e1t."}, {"title": "M\u1ee5c ti\u00eau", "body": "Chia nh\u1ecf m\u1ee5c ti\u00eau n\u0103m th\u00e0nh c\u00e1c m\u1ed1c qu\u00fd \u0111\u1ec3 theo d\u00f5i ti\u1ebfn \u0111\u1ed9."}, {"title": "C\u00e2n b\u1eb1ng", "body": "Gi\u1eef nh\u1ecbp ph\u1ee5c h\u1ed3i \u0111\u1ec3 \u0111\u1ea3m b\u1ea3o hi\u1ec7u su\u1ea5t d\u00e0i h\u1ea1n."}]}$json$::jsonb),
    (v_release_id, 'year_personal_number', '9', $json${"keyword": "Ho\u00e0n t\u1ea5t", "hero_title": "N\u0103m c\u00e1 nh\u00e2n 9", "theme": ["N\u0103m 9 l\u00e0 giai \u0111o\u1ea1n ho\u00e0n thi\u1ec7n chu k\u1ef3, bu\u00f4ng b\u1ecf \u0111i\u1ec1u c\u0169 v\u00e0 chu\u1ea9n b\u1ecb \u0111\u1ed5i pha.", "B\u1ea1n ph\u00f9 h\u1ee3p \u0111\u1ec3 t\u1ed5ng k\u1ebft, k\u1ebft th\u00fac c\u00e1c cam k\u1ebft kh\u00f4ng c\u00f2n gi\u00e1 tr\u1ecb v\u00e0 thanh l\u1ecdc h\u1ec7 th\u1ed1ng.", "Khi bi\u1ebft bu\u00f4ng \u0111\u00fang l\u00fac, b\u1ea1n s\u1ebd c\u00f3 kh\u00f4ng gian m\u1ea1nh m\u1ebd cho chu k\u1ef3 ti\u1ebfp theo."], "lessons": [{"title": "Kh\u00e9p v\u00f2ng", "body": "Ho\u00e0n t\u1ea5t c\u00e1c vi\u1ec7c c\u00f2n dang d\u1edf \u0111\u1ec3 gi\u1ea3i ph\u00f3ng n\u0103ng l\u01b0\u1ee3ng."}, {"title": "Bu\u00f4ng b\u1ecf", "body": "D\u1eebng nh\u1eefng cam k\u1ebft kh\u00f4ng c\u00f2n ph\u00f9 h\u1ee3p v\u1edbi \u0111\u1ecbnh h\u01b0\u1edbng m\u1edbi."}, {"title": "T\u1ed5ng k\u1ebft", "body": "R\u00fat b\u00e0i h\u1ecdc t\u1eeb c\u1ea3 chu k\u1ef3 v\u00e0 chu\u1ea9n b\u1ecb n\u1ec1n cho n\u0103m k\u1ebf ti\u1ebfp."}], "focus_areas": [{"title": "S\u1ef1 nghi\u1ec7p", "body": "R\u00e0 so\u00e1t danh m\u1ee5c d\u1ef1 \u00e1n, gi\u1eef c\u00e1i hi\u1ec7u qu\u1ea3 v\u00e0 \u0111\u00f3ng c\u00e1i d\u01b0 th\u1eeba."}, {"title": "T\u00e0i ch\u00ednh", "body": "D\u1ecdn c\u1ea5u tr\u00fac chi ph\u00ed v\u00e0 t\u1ed1i \u01b0u d\u00f2ng ti\u1ec1n tr\u01b0\u1edbc chu k\u1ef3 m\u1edbi."}, {"title": "M\u1ee5c ti\u00eau", "body": "T\u1ed5ng k\u1ebft th\u00e0nh qu\u1ea3 v\u00e0 t\u00e1i \u0111\u1ecbnh ngh\u0129a m\u1ee5c ti\u00eau d\u00e0i h\u1ea1n."}, {"title": "C\u00e2n b\u1eb1ng", "body": "\u01afu ti\u00ean ch\u1eefa l\u00e0nh, ngh\u1ec9 ng\u01a1i v\u00e0 t\u00e1i t\u1ea1o n\u0103ng l\u01b0\u1ee3ng s\u00e2u."}]}$json$::jsonb);
  insert into public.numerology_ledger_releases (locale, version, status, notes)
  insert into public.numerology_contents (release_id, content_type, number_key, payload_jsonb)
  values
    (v_release_id, 'universal_day', '1', $json${"title": "Initiation Energy", "energy_theme": "Today carries the vibration of leadership, initiative, and fresh starts.", "meaning": "In numerology, Universal Day 1 symbolizes beginnings, independence, and personal leadership. This energy supports proactive choices and opening new directions.", "energy_manifestation": "You may notice faster momentum today: quick decisions, strong motivation to launch something new, and a desire to lead instead of waiting for conditions to be perfect.", "keywords": ["Beginning", "Pioneer", "Initiative", "Decisive"]}$json$::jsonb),
    (v_release_id, 'universal_day', '2', $json${"title": "Balance Energy", "energy_theme": "Today favors cooperation, emotional alignment, and gentle communication.", "meaning": "Universal Day 2 represents harmony, diplomacy, and partnership. It is a day to listen deeply, collaborate effectively, and stabilize relationships.", "energy_manifestation": "Conversations may require more sensitivity than usual. It is a good time for mediation, teamwork, and restoring trust through calm and respectful exchanges.", "keywords": ["Harmony", "Connection", "Listening", "Cooperation"]}$json$::jsonb),
    (v_release_id, 'universal_day', '3', $json${"title": "Expression Energy", "energy_theme": "Today opens a creative and communicative flow with lighter emotions.", "meaning": "Universal Day 3 is linked to self-expression, creativity, and social warmth. The energy supports sharing ideas and engaging with others in an uplifting way.", "energy_manifestation": "You may find it easier to speak up, present ideas, or produce creative work. Social interactions tend to feel more open and inspiring.", "keywords": ["Creativity", "Communication", "Inspiration", "Joy"]}$json$::jsonb),
    (v_release_id, 'universal_day', '4', $json${"title": "Foundation Energy", "energy_theme": "Today highlights discipline, structure, and practical execution.", "meaning": "Universal Day 4 symbolizes stability, responsibility, and long-term building. It is ideal for planning, organizing, and making steady progress.", "energy_manifestation": "You may feel the need to prioritize, systemize, and complete pending tasks step by step. Reliability matters more than speed.", "keywords": ["Discipline", "Stability", "Organization", "Practical"]}$json$::jsonb),
    (v_release_id, 'universal_day', '5', $json${"title": "Change Energy", "energy_theme": "Today encourages flexibility, curiosity, and movement.", "meaning": "Universal Day 5 represents freedom, change, and exploration. This energy supports trying new approaches and adapting quickly to opportunities.", "energy_manifestation": "Unexpected schedule shifts or spontaneous opportunities may appear. It is a strong day to experiment, pivot, and widen your perspective.", "keywords": ["Flexibility", "Freedom", "Exploration", "Innovation"]}$json$::jsonb),
    (v_release_id, 'universal_day', '6', $json${"title": "Care Energy", "energy_theme": "Today focuses on care, responsibility, and relational harmony.", "meaning": "Universal Day 6 symbolizes compassion, nurturing, and service. It supports strengthening family bonds, trusted relationships, and emotional balance.", "energy_manifestation": "Themes around home, relationships, or caregiving may become more visible. Kindness, support, and healthy boundaries are especially important.", "keywords": ["Compassion", "Responsibility", "Support", "Harmony"]}$json$::jsonb),
    (v_release_id, 'universal_day', '7', $json${"title": "Reflection Energy", "energy_theme": "Today is best for slowing down, observing, and going inward.", "meaning": "Universal Day 7 represents wisdom, intuition, and spiritual depth. It is ideal for study, contemplation, and finding answers beneath surface noise.", "energy_manifestation": "You may need more quiet time to think clearly. Important decisions benefit from thoughtful reflection rather than instant reactions.", "keywords": ["Intuition", "Inner Work", "Reflection", "Insight"]}$json$::jsonb),
    (v_release_id, 'universal_day', '8', $json${"title": "Achievement Energy", "energy_theme": "Today favors measurable results, strategy, and leadership under pressure.", "meaning": "Universal Day 8 is associated with power, performance, and material success. It supports decisive action toward concrete goals.", "energy_manifestation": "Work, finance, and productivity topics may stand out. This energy pushes you to make data-driven choices and execute with clarity.", "keywords": ["Achievement", "Performance", "Strategy", "Finance"]}$json$::jsonb),
    (v_release_id, 'universal_day', '9', $json${"title": "Completion Energy", "energy_theme": "Today carries the rhythm of closure, release, and transition.", "meaning": "Universal Day 9 symbolizes completion, compassion, and broader perspective. It is a good day to close old cycles and prepare for what comes next.", "energy_manifestation": "You may feel called to finish lingering tasks, let go of outdated patterns, or resolve emotional weight from the past. This clears space for renewal.", "keywords": ["Completion", "Release", "Compassion", "Transformation"]}$json$::jsonb),
    (v_release_id, 'daily_message', '1', $json${"variants": [{"main_message": "H\u00f4m nay l\u00e0 ng\u00e0y \u0111\u1ec3 b\u1ea1n d\u1eabn d\u1eaft", "sub_message": "N\u0103ng l\u01b0\u1ee3ng s\u1ed1 1 mang \u0111\u1ebfn cho b\u1ea1n s\u1ee9c m\u1ea1nh ti\u00ean phong. \u0110\u1eebng ch\u1edd \u0111\u1ee3i - h\u00e3y h\u00e0nh \u0111\u1ed9ng ngay!", "hint_action": "B\u1eaft \u0111\u1ea7u m\u1ed9t d\u1ef1 \u00e1n m\u1edbi ho\u1eb7c \u0111\u01b0a ra quy\u1ebft \u0111\u1ecbnh quan tr\u1ecdng m\u00e0 b\u1ea1n \u0111\u00e3 tr\u00ec ho\u00e3n", "thinking": "Take a few minutes to reflect on this message. What does it mean for your current situation? How can you apply this guidance today?", "tips": ["Write this message in your journal to track your growth", "Set this message as a reminder to stay focused during the day", "Share with a loved one if this message feels meaningful", "Revisit at the end of the day to see how it supported you"]}, {"main_message": "Kh\u1eb3ng \u0111\u1ecbnh b\u1ea3n th\u00e2n c\u1ee7a b\u1ea1n", "sub_message": "S\u1ef1 t\u1ef1 tin \u0111ang \u1edf \u0111\u1ec9nh cao. H\u00e3y \u0111\u1ec3 th\u1ebf gi\u1edbi th\u1ea5y \u0111\u01b0\u1ee3c con ng\u01b0\u1eddi th\u1eadt c\u1ee7a b\u1ea1n.", "hint_action": "Chia s\u1ebb \u00fd t\u01b0\u1edfng s\u00e1ng t\u1ea1o ho\u1eb7c kh\u1edfi x\u01b0\u1edbng m\u1ed9t ho\u1ea1t \u0111\u1ed9ng m\u00e0 b\u1ea1n \u0111am m\u00ea", "thinking": "Take a few minutes to reflect on this message. What does it mean for your current situation? How can you apply this guidance today?", "tips": ["Write this message in your journal to track your growth", "Set this message as a reminder to stay focused during the day", "Share with a loved one if this message feels meaningful", "Revisit at the end of the day to see how it supported you"]}, {"main_message": "B\u1ea1n sinh ra \u0111\u1ec3 d\u1eabn \u0111\u1ea7u", "sub_message": "N\u0103ng l\u01b0\u1ee3ng l\u00e3nh \u0111\u1ea1o t\u1ef1 nhi\u00ean c\u1ee7a b\u1ea1n \u0111ang t\u1ecfa s\u00e1ng r\u1ef1c r\u1ee1 h\u00f4m nay.", "hint_action": "T\u00ecnh nguy\u1ec7n \u0111\u1ee9ng ra t\u1ed5 ch\u1ee9c ho\u1eb7c d\u1eabn d\u1eaft m\u1ed9t nh\u00f3m/d\u1ef1 \u00e1n", "thinking": "Take a few minutes to reflect on this message. What does it mean for your current situation? How can you apply this guidance today?", "tips": ["Write this message in your journal to track your growth", "Set this message as a reminder to stay focused during the day", "Share with a loved one if this message feels meaningful", "Revisit at the end of the day to see how it supported you"]}], "variant_strategy": "day_of_year_mod"}$json$::jsonb),
    (v_release_id, 'daily_message', '2', $json${"variants": [{"main_message": "K\u1ebft n\u1ed1i t\u1ea1o n\u00ean s\u1ee9c m\u1ea1nh", "sub_message": "H\u00f4m nay l\u00e0 ng\u00e0y \u0111\u1ec3 x\u00e2y d\u1ef1ng c\u1ea7u n\u1ed1i, kh\u00f4ng ph\u1ea3i h\u00e0ng r\u00e0o. H\u1ee3p t\u00e1c s\u1ebd mang \u0111\u1ebfn \u0111i\u1ec1u k\u1ef3 di\u1ec7u.", "hint_action": "Ch\u1ee7 \u0111\u1ed9ng li\u00ean h\u1ec7 v\u1edbi ai \u0111\u00f3 \u0111\u1ec3 h\u1ee3p t\u00e1c ho\u1eb7c h\u00e0n g\u1eafn m\u1ed1i quan h\u1ec7", "thinking": "Take a few minutes to reflect on this message. What does it mean for your current situation? How can you apply this guidance today?", "tips": ["Write this message in your journal to track your growth", "Set this message as a reminder to stay focused during the day", "Share with a loved one if this message feels meaningful", "Revisit at the end of the day to see how it supported you"]}, {"main_message": "H\u00f2a h\u1ee3p l\u00e0 ch\u00eca kh\u00f3a", "sub_message": "S\u1ef1 d\u1ecbu d\u00e0ng v\u00e0 th\u1ea5u hi\u1ec3u c\u1ee7a b\u1ea1n c\u00f3 th\u1ec3 ch\u1eefa l\u00e0nh nhi\u1ec1u v\u1ebft th\u01b0\u01a1ng h\u00f4m nay.", "hint_action": "L\u00e0m h\u00f2a gi\u1ea3i trong m\u1ed9t xung \u0111\u1ed9t ho\u1eb7c g\u1eedi l\u1eddi c\u1ea3m \u01a1n \u0111\u1ebfn ng\u01b0\u1eddi quan tr\u1ecdng", "thinking": "Take a few minutes to reflect on this message. What does it mean for your current situation? How can you apply this guidance today?", "tips": ["Write this message in your journal to track your growth", "Set this message as a reminder to stay focused during the day", "Share with a loved one if this message feels meaningful", "Revisit at the end of the day to see how it supported you"]}, {"main_message": "L\u1eafng nghe ti\u1ebfng n\u00f3i b\u00ean trong", "sub_message": "Tr\u1ef1c gi\u00e1c c\u1ee7a b\u1ea1n \u0111ang g\u1eedi nh\u1eefng th\u00f4ng \u0111i\u1ec7p quan tr\u1ecdng. H\u00e3y ch\u00fa \u00fd l\u1eafng nghe.", "hint_action": "D\