    (v_release_id, 'daily_message', '3', $json${"variants": [{"main_message": "H\u00e3y t\u1ecfa s\u00e1ng v\u1edbi s\u1ef1 s\u00e1ng t\u1ea1o", "sub_message": "Kh\u1ea3 n\u0103ng bi\u1ec3u \u0111\u1ea1t c\u1ee7a b\u1ea1n \u0111ang \u1edf \u0111\u1ec9nh cao. Th\u1ebf gi\u1edbi \u0111ang ch\u1edd \u0111\u1ee3i c\u00e2u chuy\u1ec7n c\u1ee7a b\u1ea1n!", "hint_action": "T\u1ea1o ra \u0111i\u1ec1u g\u00ec \u0111\u00f3 - vi\u1ebft, v\u1ebd, h\u00e1t, ho\u1eb7c chia s\u1ebb \u00fd t\u01b0\u1edfng v\u1edbi m\u1ecdi ng\u01b0\u1eddi", "thinking": "Take a few minutes to reflect on this message. What does it mean for your current situation? How can you apply this guidance today?", "tips": ["Write this message in your journal to track your growth", "Set this message as a reminder to stay focused during the day", "Share with a loved one if this message feels meaningful", "Revisit at the end of the day to see how it supported you"]}, {"main_message": "L\u1eddi n\u00f3i c\u1ee7a b\u1ea1n c\u00f3 s\u1ee9c m\u1ea1nh", "sub_message": "H\u00f4m nay l\u00e0 ng\u00e0y tuy\u1ec7t v\u1eddi \u0111\u1ec3 truy\u1ec1n c\u1ea3m h\u1ee9ng v\u00e0 lan t\u1ecfa ni\u1ec1m vui \u0111\u1ebfn ng\u01b0\u1eddi kh\u00e1c.", "hint_action": "G\u1ecdi \u0111i\u1ec7n cho b\u1ea1n b\u00e8 c\u0169 ho\u1eb7c t\u1ed5 ch\u1ee9c m\u1ed9t bu\u1ed5i g\u1eb7p m\u1eb7t vui v\u1ebb", "thinking": "Take a few minutes to reflect on this message. What does it mean for your current situation? How can you apply this guidance today?", "tips": ["Write this message in your journal to track your growth", "Set this message as a reminder to stay focused during the day", "Share with a loved one if this message feels meaningful", "Revisit at the end of the day to see how it supported you"]}, {"main_message": "Ni\u1ec1m vui l\u00e0 ngu\u1ed3n n\u0103ng l\u01b0\u1ee3ng", "sub_message": "S\u1ef1 l\u1ea1c quan c\u1ee7a b\u1ea1n nh\u01b0 \u00e1nh s\u00e1ng m\u1eb7t tr\u1eddi, s\u01b0\u1edfi \u1ea5m m\u1ecdi ng\u01b0\u1eddi xung quanh.", 